export default DungeonTab;

import { GameState, ManualDungeonSession, RoomType, DungeonResult } from '../../types/game-state';
import { DUNGEONS } from '../../data/dungeons';
import { handleClaimExpedition } from './expedition';
import { TILLY_FOOTLOOSE } from '../../data/mercenaries';
import { MONSTERS } from '../../data/monsters';
import { calculateMaxHp, calculateMaxMp, mergePrimaryStats } from '../../models/Stats';

const generateManualGrid = (width: number, height: number, locked: boolean, dungeonId: string, knownMercs: any[]) => {
    const grid: RoomType[][] = Array.from({ length: height }, () => Array(width).fill('EMPTY'));
    const visited: boolean[][] = Array.from({ length: height }, () => Array(width).fill(false));

    const startX = Math.floor(Math.random() * width);
    const startY = Math.floor(Math.random() * height);
    grid[startY][startX] = 'ENTRANCE';
    visited[startY][startX] = true;

    let bossX, bossY;
    do {
        bossX = Math.floor(Math.random() * width);
        bossY = Math.floor(Math.random() * height);
    } while (Math.abs(bossX - startX) + Math.abs(bossY - startY) < 2);
    grid[bossY][bossX] = 'BOSS';

    if (locked) {
        let keyX, keyY;
        do {
            keyX = Math.floor(Math.random() * width);
            keyY = Math.floor(Math.random() * height);
        } while (grid[keyY][keyX] !== 'EMPTY');
        grid[keyY][keyX] = 'KEY';
    }

    if (dungeonId === 'dungeon_t1_rats' && !knownMercs.some(m => m.id === 'tilly_footloose')) {
        let npcX, npcY;
        do {
            npcX = Math.floor(Math.random() * width);
            npcY = Math.floor(Math.random() * height);
        } while (grid[npcY][npcX] !== 'EMPTY');
        grid[npcY][npcX] = 'NPC';
    }

    const totalTiles = width * height;
    const goldSpawnChance = 1 / totalTiles;
    const trapSpawnChance = 1 / totalTiles;

    for (let y = 0; y < height; y++) {
        for (let x = 0; x < width; x++) {
            if (grid[y][x] === 'EMPTY') {
                const roll = Math.random();
                if (roll < goldSpawnChance) {
                    grid[y][x] = 'GOLD';
                } else if (roll < goldSpawnChance + trapSpawnChance) {
                    grid[y][x] = 'TRAP';
                }
            }
        }
    }

    return { grid, visited, playerPos: { x: startX, y: startY } };
};

export const handleStartManualDungeon = (state: GameState, payload: { dungeonId: string, partyIds: string[] }): GameState => {
    const dungeon = DUNGEONS.find(d => d.id === payload.dungeonId);
    if (!dungeon) return state;

    const { grid, visited, playerPos } = generateManualGrid(
        dungeon.gridWidth, 
        dungeon.gridHeight, 
        !!dungeon.isBossLocked,
        dungeon.id,
        state.knownMercenaries
    );

    let bossEntity = undefined;
    if (dungeon.id === 'dungeon_t1_rats') {
        bossEntity = { ...MONSTERS.rat_man };
    }

    const session: ManualDungeonSession = {
        dungeonId: dungeon.id,
        partyIds: payload.partyIds,
        grid,
        visited,
        playerPos,
        pathHistory: [{ ...playerPos }], 
        hasKey: false,
        isBossLocked: !!dungeon.isBossLocked,
        isBossDefeated: false,
        bossEntity,
        goldCollected: 0,
        encounterStatus: 'NONE'
    };

    const updatedMercenaries = state.knownMercenaries.map(m => {
        if (payload.partyIds.includes(m.id)) {
            return { ...m, status: 'ON_EXPEDITION' as const };
        }
        return m;
    });

    return {
        ...state,
        knownMercenaries: updatedMercenaries,
        activeManualDungeon: session,
        showManualDungeonOverlay: true,
        logs: [`Squad has entered ${dungeon.name}. Tactical scanners active.`, ...state.logs]
    };
};

export const handleMoveManualDungeon = (state: GameState, payload: { x: number, y: number }): GameState => {
    const session = state.activeManualDungeon;
    if (!session || session.encounterStatus === 'ENCOUNTERED' || session.encounterStatus === 'BATTLE') return state;

    const dungeon = DUNGEONS.find(d => d.id === session.dungeonId);
    if (!dungeon) return state;

    const newX = session.playerPos.x + payload.x;
    const newY = session.playerPos.y + payload.y;

    if (newX < 0 || newX >= dungeon.gridWidth || newY < 0 || newY >= dungeon.gridHeight) {
        return {
            ...state,
            toastQueue: [...state.toastQueue, "Reached area boundary. Navigation impossible."]
        };
    }

    const targetRoom = session.grid[newY][newX];
    if (targetRoom === 'WALL') {
        return {
            ...state,
            toastQueue: [...state.toastQueue, "A massive obstruction blocks the path."]
        };
    }

    const isAlreadyVisited = session.visited[newY][newX];
    const cost = isAlreadyVisited ? -1 : (targetRoom === 'BOSS' ? dungeon.bossEnergy : dungeon.moveEnergy);

    const party = state.knownMercenaries.filter(m => session.partyIds.includes(m.id));
    if (cost > 0 && party.some(m => (m.expeditionEnergy || 0) < cost)) {
        return { ...state, logs: [`Your squad is too exhausted to move further.`, ...state.logs] };
    }

    if (targetRoom === 'BOSS' && session.isBossLocked && !session.hasKey) {
        return { ...state, logs: [`The Boss chamber is sealed. You need a key.`, ...state.logs] };
    }

    let updatedMercs = state.knownMercenaries.map(m => {
        if (session.partyIds.includes(m.id)) {
            let nextEnergy = Math.max(0, (m.expeditionEnergy || 0) - cost);
            let nextHp = m.currentHp;
            if (targetRoom === 'TRAP' && !isAlreadyVisited) nextHp = Math.max(0, m.currentHp - 25);
            return { ...m, expeditionEnergy: nextEnergy, currentHp: nextHp };
        }
        return m;
    });

    const newVisited = [...session.visited.map(row => [...row])];
    newVisited[newY][newX] = true;

    let extraGold = 0;
    let newGrid = [...session.grid.map(row => [...row])];
    let logMsg = '';
    let encounterStatus: ManualDungeonSession['encounterStatus'] = 'NONE';

    if (targetRoom === 'GOLD' && !isAlreadyVisited) {
        extraGold = (dungeon.tier || 1) * 50;
        newGrid[newY][newX] = 'EMPTY';
        logMsg = `Treasury cache secured. (+${extraGold} G)`;
    } else if (targetRoom === 'TRAP' && !isAlreadyVisited) {
        logMsg = `AMBUSH: Traps detected. Squad took heavy damage. (-25 HP)`;
    } else if (targetRoom === 'KEY' && !isAlreadyVisited) {
        logMsg = `Chamber key recovered.`;
        newGrid[newY][newX] = 'EMPTY';
    } else if (targetRoom === 'BOSS' && !session.isBossDefeated) {
        encounterStatus = 'ENCOUNTERED';
        logMsg = `CRITICAL ALERT: ${session.bossEntity?.name} identified. Defense systems active.`;
    }

    const newPathHistory = [{ x: newX, y: newY }, ...session.pathHistory].slice(0, 50);

    return {
        ...state,
        knownMercenaries: updatedMercs,
        activeManualDungeon: {
            ...session,
            grid: newGrid,
            playerPos: { x: newX, y: newY },
            pathHistory: newPathHistory,
            visited: newVisited,
            hasKey: targetRoom === 'KEY' ? true : session.hasKey,
            encounterStatus,
            goldCollected: session.goldCollected + extraGold
        },
        logs: logMsg ? [logMsg, ...state.logs] : state.logs
    };
};

export const handleStartCombatManual = (state: GameState): GameState => {
    if (!state.activeManualDungeon) return state;
    return {
        ...state,
        activeManualDungeon: {
            ...state.activeManualDungeon,
            encounterStatus: 'BATTLE'
        }
    };
};

export const handleResolveCombatManual = (state: GameState, payload: { win: boolean, flee: boolean, finalParty: any[] }): GameState => {
    const session = state.activeManualDungeon;
    if (!session) return state;

    // Sync stats from combat
    const newKnownMercenaries = state.knownMercenaries.map(m => {
        const combatant = payload.finalParty.find(p => p.id === m.id);
        if (combatant) {
            return { ...m, currentHp: combatant.currentHp, currentMp: combatant.currentMp };
        }
        return m;
    });

    let nextStatus: ManualDungeonSession['encounterStatus'] = payload.win ? 'VICTORY' : (payload.flee ? 'NONE' : 'DEFEAT');
    let nextPos = session.playerPos;
    let nextHistory = session.pathHistory;

    // Back off to previous safe tile on flee
    if (payload.flee) {
        nextPos = session.pathHistory[1] || session.playerPos;
        nextHistory = session.pathHistory.slice(1);
    }

    return {
        ...state,
        knownMercenaries: newKnownMercenaries,
        activeManualDungeon: {
            ...session,
            playerPos: nextPos,
            pathHistory: nextHistory,
            encounterStatus: nextStatus,
            isBossDefeated: payload.win || session.isBossDefeated
        },
        logs: payload.flee ? ['TACTICAL WITHDRAWAL: Back to safe zone.', ...state.logs] : state.logs
    };
};

export const handleFinishManualDungeon = (state: GameState): GameState => {
    const session = state.activeManualDungeon;
    if (!session) return state;

    const dummyExpId = `manual_clear_${Date.now()}`;
    const tempState: GameState = {
        ...state,
        activeExpeditions: [{
            id: dummyExpId, dungeonId: session.dungeonId, partyIds: session.partyIds,
            startTime: Date.now(), endTime: Date.now(), status: 'COMPLETED' as const
        }]
    };

    const finalState = handleClaimExpedition(tempState, { expeditionId: dummyExpId, rescuedNpcId: session.rescuedNpcId });
    const totalManualGold = session.goldCollected;

    // Check if any mercenary returned with 0 HP and set INJURED status
    const checkedMercenaries = finalState.knownMercenaries.map(m => {
        if (session.partyIds.includes(m.id) && m.currentHp < 1) {
            return { 
                ...m, 
                status: 'INJURED' as const, 
                recoveryUntilDay: finalState.stats.day + Math.floor(Math.random() * 2) + 1 
            };
        }
        return m;
    });

    return { 
        ...finalState, 
        knownMercenaries: checkedMercenaries,
        stats: {
            ...finalState.stats,
            gold: finalState.stats.gold + totalManualGold,
            dailyFinancials: { ...finalState.stats.dailyFinancials, incomeDungeon: finalState.stats.dailyFinancials.incomeDungeon + totalManualGold }
        },
        activeManualDungeon: null, 
        showManualDungeonOverlay: false 
    };
};

export const handleRetreatManualDungeon = (state: GameState): GameState => {
    const session = state.activeManualDungeon;
    if (!session) return state;

    const isDefeat = session.encounterStatus === 'DEFEAT';
    const dungeon = DUNGEONS.find(d => d.id === session.dungeonId);

    const mercResults: DungeonResult['mercenaryResults'] = [];
    const updatedMercs = state.knownMercenaries.map(m => {
        if (session.partyIds.includes(m.id)) {
            let nextStatus: any = 'HIRED';
            let statusChange: 'NONE' | 'INJURED' | 'DEAD' = 'NONE';
            let recoveryUntilDay: number | undefined = undefined;

            // If they have 0 HP, they are definitely injured
            const isUnconscious = m.currentHp < 1;

            if (isDefeat) {
                const roll = Math.random();
                if (roll < 0.15) { 
                    nextStatus = 'DEAD'; 
                    statusChange = 'DEAD'; 
                }
                else {
                    nextStatus = 'INJURED'; 
                    statusChange = 'INJURED'; 
                    recoveryUntilDay = state.stats.day + Math.floor(Math.random() * 3) + 1;
                }
            } else if (isUnconscious) {
                nextStatus = 'INJURED'; 
                statusChange = 'INJURED'; 
                recoveryUntilDay = state.stats.day + Math.floor(Math.random() * 2) + 1;
            }

            mercResults.push({
                id: m.id, name: m.name, job: m.job, levelBefore: m.level, levelAfter: m.level,
                xpGained: 0, currentXp: m.currentXp, xpToNext: m.xpToNextLevel, statusChange
            });

            return { 
                ...m, 
                status: nextStatus, 
                assignedExpeditionId: undefined,
                recoveryUntilDay 
            };
        }
        return m;
    });

    return {
        ...state,
        knownMercenaries: updatedMercs,
        dungeonResult: isDefeat ? {
            dungeonName: dungeon?.name || 'Unknown',
            rewards: [],
            goldGained: 0,
            mercenaryResults: mercResults,
            isDefeat: true
        } : state.dungeonResult,
        activeManualDungeon: null,
        showManualDungeonOverlay: false,
        logs: [isDefeat ? 'CRITICAL FAILURE: The squad has been wiped out.' : 'The squad retreated to safety.', ...state.logs]
    };
};

export const handleRescueNPC = (state: GameState, payload: { npcId: string }): GameState => {
    const currentSession = state.activeManualDungeon;
    if (!currentSession) return state;

    let newGrid = [...currentSession.grid.map(row => [...row])];
    newGrid[currentSession.playerPos.y][currentSession.playerPos.x] = 'EMPTY';

    return {
        ...state,
        activeManualDungeon: { ...currentSession, grid: newGrid, npcFound: true, rescuedNpcId: payload.npcId },
        logs: [`Rescue initiated for survivor. Secure the area for extraction.`, ...state.logs]
    };
};

import { GameState, InventoryItem, DungeonResult } from '../../types/index';
import { DUNGEONS } from '../../data/dungeons';
import { Expedition } from '../../models/Dungeon';
import { MATERIALS } from '../../data/materials';
import { calculateMaxHp, calculateMaxMp, mergePrimaryStats } from '../../models/Stats';
import { TILLY_FOOTLOOSE } from '../../data/mercenaries';

export const handleStartExpedition = (state: GameState, payload: { dungeonId: string; partyIds: string[] }): GameState => {
    const { dungeonId, partyIds } = payload;
    const dungeon = DUNGEONS.find(d => d.id === dungeonId);
    if (!dungeon) return state;

    const newExpeditionId = `exp_${Date.now()}`;

    const updatedMercenaries = state.knownMercenaries.map(merc => {
        if (partyIds.includes(merc.id)) {
            return {
                ...merc,
                expeditionEnergy: Math.max(0, (merc.expeditionEnergy || 0) - dungeon.energyCost),
                status: 'ON_EXPEDITION' as const,
                assignedExpeditionId: newExpeditionId
            };
        }
        return merc;
    });

    const newExpedition: Expedition = {
        id: newExpeditionId,
        dungeonId: dungeon.id,
        partyIds: partyIds,
        startTime: Date.now(),
        endTime: Date.now() + (dungeon.durationMinutes * 60 * 1000),
        status: 'ACTIVE'
    };

    return {
        ...state,
        knownMercenaries: updatedMercenaries,
        activeExpeditions: [...state.activeExpeditions, newExpedition],
        logs: [`Expedition sent to ${dungeon.name}.`, ...state.logs]
    };
};

export const handleCompleteExpedition = (state: GameState, payload: { expeditionId: string }): GameState => {
    const { expeditionId } = payload;
    const expedition = state.activeExpeditions.find(e => e.id === expeditionId);

    if (!expedition || expedition.status !== 'ACTIVE') return state;

    const dungeon = DUNGEONS.find(d => d.id === expedition.dungeonId);
    const dungeonName = dungeon ? dungeon.name : 'Unknown';

    const updatedExpeditions = state.activeExpeditions.map(exp => {
        if (exp.id === expeditionId) {
            return { ...exp, status: 'COMPLETED' as const };
        }
        return exp;
    });

    return {
        ...state,
        activeExpeditions: updatedExpeditions,
        logs: [`Expedition to ${dungeonName} is ready for return.`, ...state.logs]
    };
};

export const handleAbortExpedition = (state: GameState, payload: { expeditionId: string }): GameState => {
    const { expeditionId } = payload;
    const expedition = state.activeExpeditions.find(e => e.id === expeditionId);
    if (!expedition) return state;

    const updatedMercs = state.knownMercenaries.map(m => {
        if (expedition.partyIds.includes(m.id)) {
            return { ...m, status: 'HIRED' as const, assignedExpeditionId: undefined };
        }
        return m;
    });

    return {
        ...state,
        knownMercenaries: updatedMercs,
        activeExpeditions: state.activeExpeditions.filter(e => e.id !== expeditionId),
        logs: [`Mission aborted. The squad has been recalled with no rewards.`, ...state.logs]
    };
};

export const handleClaimExpedition = (state: GameState, payload: { expeditionId: string; rescuedNpcId?: string }): GameState => {
    const { expeditionId, rescuedNpcId } = payload;
    const expedition = state.activeExpeditions.find(e => e.id === expeditionId);
    if (!expedition) return state;

    const dungeon = DUNGEONS.find(d => d.id === expedition.dungeonId);
    if (!dungeon) return state;

    const partyMembers = state.knownMercenaries.filter(m => expedition.partyIds.includes(m.id));
    const totalLuck = partyMembers.reduce((sum, m) => sum + (m.stats.luk + m.allocatedStats.luk), 0);
    const avgLuck = totalLuck / (partyMembers.length || 1);
    const luckMultiplier = 1 + (avgLuck * 0.02);

    const gainedItems: { id: string, count: number, name: string }[] = [];
    let newInventory = [...state.inventory];

    dungeon.rewards.forEach(reward => {
            const adjustedChance = reward.chance * luckMultiplier;
            if (Math.random() <= adjustedChance) {
                const quantity = Math.floor(Math.random() * (reward.maxQuantity - reward.minQuantity + 1)) + reward.minQuantity;
                if (quantity > 0) {
                    const materialDef = Object.values(MATERIALS).find(m => m.id === reward.itemId);
                    if (materialDef) {
                        const existingItem = newInventory.find(i => i.id === reward.itemId);
                        if (existingItem) {
                            newInventory = newInventory.map(i => i.id === reward.itemId ? { ...i, quantity: i.quantity + quantity } : i);
                        } else {
                            newInventory.push({ ...materialDef, quantity } as InventoryItem);
                        }
                        gainedItems.push({ id: reward.itemId, count: quantity, name: materialDef.name });
                    }
                }
            }
    });

    const goldGained = dungeon.goldReward || 0;

    const isFirstClear = (state.dungeonClearCounts[dungeon.id] || 0) === 0;
    if (isFirstClear && dungeon.id === 'dungeon_t1_rats') {
        const scrollDef = MATERIALS.RECIPE_SCROLL_BRONZE_LONGSWORD;
        const alreadyHasScroll = newInventory.some(i => i.id === scrollDef.id);
        const alreadyHasRecipe = state.unlockedRecipes.includes('sword_bronze_long_t1');

        if (!alreadyHasScroll && !alreadyHasRecipe) {
            newInventory.push({ ...scrollDef, quantity: 1 } as InventoryItem);
            gainedItems.push({ id: scrollDef.id, count: 1, name: scrollDef.name });
        }
    }

    const mercenaryResults: DungeonResult['mercenaryResults'] = [];
    let newKnownMercenaries = [...state.knownMercenaries];

    // Process XP for party and handle health-based status changes
    newKnownMercenaries = newKnownMercenaries.map(merc => {
        if (expedition.partyIds.includes(merc.id)) {
            let xpToAdd = dungeon.baseXp || 50;
            let currentXp = merc.currentXp || 0;
            let xpToNext = merc.xpToNextLevel || (merc.level * 100);
            let level = merc.level;
            const levelBefore = level;

            currentXp += xpToAdd;

            while (currentXp >= xpToNext) {
                currentXp -= xpToNext;
                level++;
                xpToNext = level * 100;
            }

            let maxHp = merc.maxHp;
            let maxMp = merc.maxMp;
            let currentHp = merc.currentHp;

            if (level > levelBefore) {
                const merged = mergePrimaryStats(merc.stats, merc.allocatedStats);
                maxHp = calculateMaxHp(merged, level);
                maxMp = calculateMaxMp(merged, level);
                currentHp = maxHp;
            }

            let nextStatus = 'HIRED' as const;
            let recoveryUntilDay: number | undefined = undefined;

            // If HP < 1, they return INJURED
            if (currentHp < 1) {
                nextStatus = 'INJURED' as const;
                recoveryUntilDay = state.stats.day + Math.floor(Math.random() * 2) + 1;
            }

            mercenaryResults.push({
                id: merc.id,
                name: merc.name,
                job: merc.job,
                levelBefore,
                levelAfter: level,
                xpGained: xpToAdd,
                currentXp: currentXp,
                xpToNext: xpToNext,
                statusChange: currentHp < 1 ? 'INJURED' : 'NONE'
            });

            return {
                ...merc,
                level,
                currentXp,
                xpToNextLevel: xpToNext,
                maxHp,
                maxMp,
                currentHp,
                status: nextStatus,
                recoveryUntilDay,
                assignedExpeditionId: undefined
            };
        }
        return merc;
    });

    // Handle Rescued NPC
    let rescuedMercenary = undefined;
    if (rescuedNpcId) {
        if (rescuedNpcId === 'tilly_footloose') {
            rescuedMercenary = { ...TILLY_FOOTLOOSE };
            if (!newKnownMercenaries.some(m => m.id === rescuedMercenary!.id)) {
                newKnownMercenaries.push(rescuedMercenary);
            }
        }
    }

    const newClearCounts = { ...state.dungeonClearCounts };
    newClearCounts[dungeon.id] = (newClearCounts[dungeon.id] || 0) + 1;
    const remainingExpeditions = state.activeExpeditions.filter(e => e.id !== expeditionId);

    const resultData: DungeonResult = {
        dungeonName: dungeon.name,
        rewards: gainedItems,
        goldGained,
        mercenaryResults,
        rescuedMercenary
    };

    const luckMsg = luckMultiplier > 1.1 ? ` (Luck Bonus x${luckMultiplier.toFixed(1)})` : '';
    let logStr = gainedItems.length > 0 
        ? `Returned from ${dungeon.name}${luckMsg}. Gained: ${gainedItems.map(i => `${i.name} x${i.count}`).join(', ')}`
        : `Returned from ${dungeon.name}. No loot found.`;

    if (goldGained > 0) logStr += ` and ${goldGained} Gold.`;

    return {
        ...state,
        inventory: newInventory,
        knownMercenaries: newKnownMercenaries,
        activeExpeditions: remainingExpeditions,
        dungeonClearCounts: newClearCounts,
        dungeonResult: resultData,
        stats: {
            ...state.stats,
            gold: state.stats.gold + goldGained,
            dailyFinancials: {
                ...state.stats.dailyFinancials,
                incomeDungeon: state.stats.dailyFinancials.incomeDungeon + goldGained
            }
        },
        logs: [logStr, ...state.logs]
    };
};

