    const [isAuto, setIsAuto] = useState(true);
    const [isPaused, setIsPaused] = useState(false);
    const [activeActorId, setActiveActorId] = useState<string | null>(null); 
    const [showLogs, setShowLogs] = useState(false);
    const battleInterval = useRef<ReturnType<typeof setInterval> | null>(null);

    const addLog = (msg: string, team: 'PLAYER' | 'ENEMY' | 'SYSTEM', isCrit = false, isSkill = false) => {
        setLogs(prev => [{ msg, team, isCrit, isSkill }, ...prev].slice(0, 50));
    };

    const triggerDamagePopup = (targetId: string, value: number, isCrit: boolean, isSkill: boolean) => {
        const id = Date.now() + Math.random();
        setDamagePopups(prev => [...prev, { id, value, targetId, isCrit, isSkill }]);
        setTimeout(() => {
            setDamagePopups(prev => prev.filter(p => p.id !== id));
        }, 800);
    };

    const executeAttack = useCallback((attacker: any, target: any, isPlayerAttacker: boolean, skillId?: string) => {
        const skill = skillId ? SKILLS[skillId] : null;
        const multiplier = skill ? skill.multiplier : 1.0;
        const mpCost = skill ? skill.mpCost : 0;

        const res = calculateCombatResult(
            isPlayerAttacker ? attacker.derived : attacker.stats,
            isPlayerAttacker ? target.stats : target.derived,
            isPlayerAttacker ? attacker.job : 'Fighter' as any,
            isPlayerAttacker ? (attacker.derived.magicalAttack > attacker.derived.physicalAttack ? 'MAGICAL' : 'PHYSICAL') : 'PHYSICAL',
            multiplier
        );

        if (isPlayerAttacker) {
            setBossState(prev => {
                const next = { ...prev, lastDamaged: res.isHit };
                if (res.isHit) {
                    next.currentHp = Math.max(0, next.currentHp - res.damage);
                    triggerDamagePopup('BOSS', res.damage, res.isCrit, !!skill);
                }
                setTimeout(() => setBossState(curr => ({ ...curr, lastDamaged: false })), 200);
                return next;
            });

            if (skill) {
                setPartyState(prev => prev.map(p => p.id === attacker.id ? { ...p, currentMp: Math.max(0, p.currentMp - mpCost) } : p));
                addLog(`${attacker.name.split(' ')[0]} uses ${skill.name}! Hit for ${res.damage}${res.isCrit ? "!" : ""}`, 'PLAYER', res.isCrit, true);
            } else {
                addLog(`${attacker.name.split(' ')[0]} hit for ${res.damage}${res.isCrit ? "!" : ""}`, 'PLAYER', res.isCrit);
            }
        } else {
            setPartyState(prev => prev.map(p => {
                if (p.id === target.id) {
                    const next = { ...p, lastDamaged: res.isHit };
                    if (res.isHit) {
                        next.currentHp = Math.max(0, next.currentHp - res.damage);
                        triggerDamagePopup(p.id, res.damage, res.isCrit, false);
                    }
                    setTimeout(() => setPartyState(curr => curr.map(c => c.id === p.id ? { ...c, lastDamaged: false } : c)), 200);
                    return next;
                }
                return p;
            }));
            addLog(`${attacker.name} struck ${target.name.split(' ')[0]} for ${res.damage}`, 'ENEMY');
        }
    }, []);

    const processLoop = useCallback(() => {
        if (isPaused || activeActorId) return;

        setPartyState(prevParty => {
            const nextParty = [...prevParty];
            setBossState(prevBoss => {
                const nextBoss = { ...prevBoss };

                nextParty.forEach(p => { if (p.currentHp > 0) p.gauge += p.derived.speed * 0.5; });
                nextBoss.gauge += nextBoss.stats.speed * 0.5;

                const readyMerc = nextParty.find(p => p.currentHp > 0 && p.gauge >= ACTION_THRESHOLD);
                if (readyMerc) {
                    if (isAuto) {
                        readyMerc.gauge -= ACTION_THRESHOLD;

                        // AI Logic: Use Skill if MP is sufficient
                        let chosenSkillId: string | undefined = undefined;
                        if (readyMerc.skillIds && readyMerc.skillIds.length > 0) {
                            const availableSkills = readyMerc.skillIds.map(id => SKILLS[id]).filter(s => readyMerc.currentMp >= s.mpCost);
                            if (availableSkills.length > 0) {
                                // Pick strongest skill (highest multiplier)
                                chosenSkillId = availableSkills.sort((a, b) => b.multiplier - a.multiplier)[0].id;
                            }
                        }
                        executeAttack(readyMerc, nextBoss, true, chosenSkillId);
                    } else {
                        setActiveActorId(readyMerc.id);
                    }
                }

                if (nextBoss.gauge >= ACTION_THRESHOLD && nextBoss.currentHp > 0 && !activeActorId) {
                    nextBoss.gauge -= ACTION_THRESHOLD;
                    const targets = nextParty.filter(p => p.currentHp > 0);
                    if (targets.length > 0) {
                        const target = targets[Math.floor(Math.random() * targets.length)];
                        executeAttack(nextBoss, target, false);
                    }
                }

                return nextBoss;
            });
            return nextParty;
        });
    }, [isPaused, isAuto, activeActorId, executeAttack]);

    useEffect(() => {
        battleInterval.current = setInterval(processLoop, 100);
        return () => { if (battleInterval.current) clearInterval(battleInterval.current); };
    }, [processLoop]);

    const handleManualCommand = (type: 'ATTACK' | 'FLEE' | 'SKILL', skillId?: string) => {
        if (!activeActorId) return;
        const actor = partyState.find(p => p.id === activeActorId);
        if (!actor) return;

        if (type === 'ATTACK' || (type === 'SKILL' && skillId)) {
            setPartyState(prev => prev.map(p => p.id === activeActorId ? { ...p, gauge: p.gauge - ACTION_THRESHOLD } : p));
            executeAttack(actor, bossState, true, skillId);
            setActiveActorId(null);
        } else if (type === 'FLEE') {
            const roll = Math.random() * 100;
            if (roll < fleeChance) {
                onFlee(partyState);
            } else {
                addLog(`${actor.name.split(' ')[0]} failed to find escape route!`, 'SYSTEM');
                setPartyState(prev => prev.map(p => p.id === activeActorId ? { ...p, gauge: p.gauge - ACTION_THRESHOLD } : p));
                setActiveActorId(null);
            }
        }
    };

    useEffect(() => {
        if (bossState.currentHp <= 0) {
            setIsPaused(true);
            setTimeout(() => onFinish(true, partyState), 1000);
        } else if (partyState.every(p => p.currentHp <= 0)) {
            setIsPaused(true);
            setTimeout(() => onFinish(false, partyState), 1000);
        }
    }, [bossState.currentHp, partyState, onFinish]);

    return (
        <div className="fixed inset-0 z-[110] flex flex-col bg-stone-950 animate-in zoom-in-95 duration-500 overflow-hidden">
            <style>{`
                @keyframes damage-float {
                    0% { transform: translateY(0); opacity: 0; }
                    20% { opacity: 1; }
                    100% { transform: translateY(-40px); opacity: 0; }
                }
                .animate-damage { animation: damage-float 0.8s ease-out forwards; }
            `}</style>

            {/* Header */}
            <div className="p-3 bg-red-950/20 border-b border-red-900/30 flex justify-between items-center shrink-0">
                <div className="flex items-center gap-2">
                    <Skull className="w-4 h-4 text-red-500" />
                    <h2 className="text-white font-black uppercase text-sm tracking-widest">Combat Phase</h2>
                </div>
                <button 
                    onClick={() => setIsAuto(!isAuto)}
                    className={`flex items-center gap-2 px-4 py-1.5 rounded-lg border font-black text-[10px] uppercase tracking-widest transition-all ${isAuto ? 'bg-amber-600 border-amber-400 text-white' : 'bg-stone-800 border-stone-600 text-stone-400'}`}
                >
                    {isAuto ? <FastForward className="w-3 h-3" /> : <Pause className="w-3 h-3" />}
                    {isAuto ? 'AUTO' : 'MANUAL'}
                </button>
            </div>

            <div className="flex-1 flex flex-col p-4 gap-4 overflow-y-auto no-scrollbar">

                {/* Boss Section */}
                <div className="flex flex-col items-center justify-center p-6 bg-stone-900/40 rounded-2xl border border-white/5 relative">
                    <div className={`relative transition-all duration-150 ${bossState.lastDamaged ? 'scale-110 brightness-150' : 'scale-100'}`}>
                        <div className="text-7xl md:text-8xl drop-shadow-[0_0_30px_rgba(239,68,68,0.3)]">{bossState.icon}</div>
                        {damagePopups.filter(p => p.targetId === 'BOSS').map(p => (
                            <div key={p.id} className={`absolute top-0 left-1/2 -translate-x-1/2 font-black text-2xl animate-damage ${p.isSkill ? 'text-blue-400 scale-150' : p.isCrit ? 'text-amber-400 scale-125' : 'text-red-500'}`}>
                                -{p.value}
                            </div>
                        ))}
                    </div>
                    <div className="mt-4 w-full max-w-xs space-y-2">
                        <div className="flex justify-between items-end">
                            <span className="text-red-100 font-bold uppercase text-xs tracking-tighter">{bossState.name}</span>
                            <span className="font-mono text-[10px] text-red-500 font-bold">{Math.floor(bossState.currentHp)} / {bossState.stats.maxHp}</span>
                        </div>
                        <div className="h-2 bg-stone-950 rounded-full overflow-hidden border border-white/5">
                            <div className="h-full bg-red-600 transition-all duration-300" style={{ width: `${(bossState.currentHp/bossState.stats.maxHp)*100}%` }} />
                        </div>
                        <div className="h-1 bg-stone-950 rounded-full overflow-hidden border border-white/5">
                            <div className="h-full bg-amber-500 transition-all duration-100" style={{ width: `${(bossState.gauge/ACTION_THRESHOLD)*100}%` }} />
                        </div>
                    </div>
                </div>

                {/* Ally Party List */}
                <div className="flex flex-col gap-2">
                    {partyState.map(p => {
                        const isActive = activeActorId === p.id;
                        return (
                            <div key={p.id} className={`bg-stone-900 border-2 rounded-xl p-3 flex flex-col gap-2 transition-all ${isActive ? 'border-amber-500 shadow-glow-sm bg-stone-850' : 'border-stone-800'} ${p.currentHp <= 0 ? 'grayscale opacity-40' : ''}`}>
                                <div className="flex gap-3">
                                    <div className="w-12 h-12 bg-stone-800 rounded-lg flex items-center justify-center text-3xl shadow-inner shrink-0 relative">
                                        {p.icon}
                                        {damagePopups.filter(dp => dp.targetId === p.id).map(dp => (
                                            <div key={dp.id} className={`absolute top-0 left-0 right-0 text-center font-black text-lg animate-damage text-red-500`}>
                                                -{dp.value}
                                            </div>
                                        ))}
                                    </div>
                                    <div className="flex-1 min-w-0 flex flex-col justify-center">
                                        <div className="flex justify-between items-end mb-1">
                                            <span className="font-black text-stone-100 text-xs uppercase truncate">{p.name}</span>
                                            <div className="flex items-center gap-2">
                                                <span className="font-mono font-black text-red-500 text-[9px]">HP {Math.floor(p.currentHp)}</span>
                                                <span className="font-mono font-black text-blue-400 text-[9px]">MP {Math.floor(p.currentMp)}</span>
                                            </div>
                                        </div>
                                        <div className="h-2 bg-stone-950 rounded-full overflow-hidden border border-white/5">
                                            <div className="h-full bg-red-600 transition-all duration-500" style={{ width: `${(p.currentHp/p.derived.maxHp)*100}%` }} />
                                        </div>
                                        <div className="h-1 bg-stone-950 rounded-full overflow-hidden mt-1 border border-white/5">
                                            <div className="h-full bg-amber-500 transition-all duration-100" style={{ width: `${(p.gauge/ACTION_THRESHOLD)*100}%` }} />
                                        </div>
                                    </div>
                                </div>

                                {/* Inline Manual Controls */}
                                {isActive && (
                                    <div className="flex flex-col gap-2 mt-1 animate-in slide-in-from-top-1 duration-200">
                                        <div className="flex gap-2">
                                            <button 
                                                onClick={() => handleManualCommand('ATTACK')}
                                                className="flex-1 py-2 bg-stone-800 hover:bg-stone-700 text-white rounded-lg font-black text-[10px] uppercase tracking-widest border-b-2 border-stone-950 active:translate-y-0.5 transition-all flex items-center justify-center gap-2"
                                            >
                                                <Sword className="w-3 h-3" /> Attack
                                            </button>
                                            <button 
                                                onClick={() => handleManualCommand('FLEE')}
                                                className="flex-1 py-2 bg-stone-700 hover:bg-red-900 text-stone-100 rounded-lg font-black text-[10px] uppercase tracking-widest border-b-2 border-stone-900 active:translate-y-0.5 transition-all flex items-center justify-center gap-2"
                                            >
                                                <LogOut className="w-3 h-3" /> Escape
                                            </button>
                                        </div>

                                        {/* Skills Section */}
                                        {p.skillIds && p.skillIds.length > 0 && (
                                            <div className="grid grid-cols-2 gap-2">
                                                {p.skillIds.map(id => {
                                                    const skill = SKILLS[id];
                                                    const canUse = p.currentMp >= skill.mpCost;
                                                    return (
                                                        <button 
                                                            key={id}
                                                            disabled={!canUse}
                                                            onClick={() => handleManualCommand('SKILL', id)}
                                                            className={`flex flex-col items-center justify-center py-1.5 rounded-lg border-b-2 transition-all ${canUse ? 'bg-amber-600 border-amber-800 hover:bg-amber-500 text-white active:translate-y-0.5' : 'bg-stone-900 border-stone-950 text-stone-600 opacity-50 cursor-not-allowed'}`}
                                                        >
                                                            <div className="flex items-center gap-1.5">
                                                                <Sparkles className="w-3 h-3" />
                                                                <span className="font-black text-[9px] uppercase">{skill.name}</span>
                                                            </div>
                                                            <span className="text-[7px] font-bold opacity-80">{skill.mpCost} MP</span>
                                                        </button>
                                                    );
                                                })}
                                            </div>
                                        )}
                                    </div>
                                )}
                            </div>
                        );
                    })}
                </div>
            </div>

            {/* Tactical Logs Section */}
            <div className={`bg-stone-900 border-t border-stone-800 transition-all duration-300 flex flex-col ${showLogs ? 'h-48' : 'h-10'}`}>
                <button 
                    onClick={() => setShowLogs(!showLogs)}
                    className="w-full h-10 flex items-center justify-between px-4 text-[10px] font-black text-stone-500 uppercase tracking-[0.2em] bg-stone-950/40 hover:bg-stone-950/60 transition-colors"
                >
                    <div className="flex items-center gap-2">
                        <Activity className={`w-3 h-3 text-red-500 ${isPaused ? '' : 'animate-pulse'}`} />
                        <span>Tactical Log Feed</span>
                    </div>
                    {showLogs ? <ChevronDown className="w-4 h-4" /> : <ChevronUp className="w-4 h-4" />}
                </button>

                <div className={`flex-1 overflow-y-auto custom-scrollbar p-2 space-y-1 bg-stone-950/20 ${showLogs ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}>
                    {logs.map((log, idx) => (
                        <div key={idx} className={`text-[10px] font-mono px-3 py-1 border-l-2 ${log.isSkill ? 'border-amber-400 bg-amber-900/10' : log.team === 'PLAYER' ? 'border-blue-500 text-blue-100' : log.team === 'ENEMY' ? 'border-red-500 text-red-100' : 'border-amber-500 text-amber-100'} ${log.isCrit ? 'font-bold underline' : ''}`}>
                            <span className="opacity-30 mr-2 text-[8px]">{new Date().toLocaleTimeString([], { hour12: false, minute: '2-digit', second: '2-digit' })}</span>
                            {log.msg}
                        </div>
                    ))}
                    {logs.length === 0 && <div className="h-full flex items-center justify-center text-stone-800 italic text-[10px] uppercase tracking-widest opacity-50">Monitoring bio-rhythms...</div>}
                </div>
            </div>
        </div>
    );
};

export default DungeonCombatView;

import { DerivedStats } from './Stats';

export interface Monster {
  id: string;
  name: string;
  level: number;
  icon: string;
  sprite?: string;
  description: string;
  // 파생 수치를 직접 정의하여 밸런싱 정밀도 향상
  stats: DerivedStats;
  currentHp: number;
  rewardXp: number; // XP granted to the party upon defeat
}

import { GameState, ManualDungeonSession, RoomType, DungeonResult } from '../../types/game-state';
import { DUNGEONS } from '../../data/dungeons';
import { handleClaimExpedition } from './expedition';
import { TILLY_FOOTLOOSE } from '../../data/mercenaries';
import { MONSTERS } from '../../data/monsters';
import { calculateMaxHp, calculateMaxMp, mergePrimaryStats } from '../../models/Stats';

const generateManualGrid = (width: number, height: number, locked: boolean, dungeonId: string, knownMercs: any[]) => {
    const grid: RoomType[][] = Array.from({ length: height }, () => Array(width).fill('EMPTY'));
    const visited: boolean[][] = Array.from({ length: height }, () => Array(width).fill(false));

    const startX = Math.floor(Math.random() * width);
    const startY = Math.floor(Math.random() * height);
    grid[startY][startX] = 'ENTRANCE';
    visited[startY][startX] = true;

    let bossX, bossY;
    do {
        bossX = Math.floor(Math.random() * width);
        bossY = Math.floor(Math.random() * height);
    } while (Math.abs(bossX - startX) + Math.abs(bossY - startY) < 2);
    grid[bossY][bossX] = 'BOSS';

    if (locked) {
        let keyX, keyY;
        do {
            keyX = Math.floor(Math.random() * width);
            keyY = Math.floor(Math.random() * height);
        } while (grid[keyY][keyX] !== 'EMPTY');
        grid[keyY][keyX] = 'KEY';
    }

    if (dungeonId === 'dungeon_t1_rats' && !knownMercs.some(m => m.id === 'tilly_footloose')) {
        let npcX, npcY;
        do {
            npcX = Math.floor(Math.random() * width);
            npcY = Math.floor(Math.random() * height);
        } while (grid[npcY][npcX] !== 'EMPTY');
        grid[npcY][npcX] = 'NPC';
    }

    const totalTiles = width * height;
    const goldSpawnChance = 1 / totalTiles;
    const trapSpawnChance = 1 / totalTiles;

    for (let y = 0; y < height; y++) {
        for (let x = 0; x < width; x++) {
            if (grid[y][x] === 'EMPTY') {
                const roll = Math.random();
                if (roll < goldSpawnChance) {
                    grid[y][x] = 'GOLD';
                } else if (roll < goldSpawnChance + trapSpawnChance) {
                    grid[y][x] = 'TRAP';
                }
            }
        }
    }

    return { grid, visited, playerPos: { x: startX, y: startY } };
};

export const handleStartManualDungeon = (state: GameState, payload: { dungeonId: string, partyIds: string[] }): GameState => {
    const dungeon = DUNGEONS.find(d => d.id === payload.dungeonId);
    if (!dungeon) return state;

    const { grid, visited, playerPos } = generateManualGrid(
        dungeon.gridWidth, 
        dungeon.gridHeight, 
        !!dungeon.isBossLocked,
        dungeon.id,
        state.knownMercenaries
    );

    let bossEntity = undefined;
    if (dungeon.id === 'dungeon_t1_rats') {
        bossEntity = { ...MONSTERS.rat_man };
    }

    const session: ManualDungeonSession = {
        dungeonId: dungeon.id,
        partyIds: payload.partyIds,
        grid,
        visited,
        playerPos,
        pathHistory: [{ ...playerPos }], 
        hasKey: false,
        isBossLocked: !!dungeon.isBossLocked,
        isBossDefeated: false,
        bossEntity,
        goldCollected: 0,
        encounterStatus: 'NONE'
    };

    const updatedMercenaries = state.knownMercenaries.map(m => {
        if (payload.partyIds.includes(m.id)) {
            return { ...m, status: 'ON_EXPEDITION' as const };
        }
        return m;
    });

    return {
        ...state,
        knownMercenaries: updatedMercenaries,
        activeManualDungeon: session,
        showManualDungeonOverlay: true,
        logs: [`Squad has entered ${dungeon.name}. Tactical scanners active.`, ...state.logs]
    };
};

export const handleMoveManualDungeon = (state: GameState, payload: { x: number, y: number }): GameState => {
    const session = state.activeManualDungeon;
    if (!session || session.encounterStatus === 'ENCOUNTERED' || session.encounterStatus === 'BATTLE') return state;

    const dungeon = DUNGEONS.find(d => d.id === session.dungeonId);
    if (!dungeon) return state;

    const newX = session.playerPos.x + payload.x;
    const newY = session.playerPos.y + payload.y;

    if (newX < 0 || newX >= dungeon.gridWidth || newY < 0 || newY >= dungeon.gridHeight) {
        return {
            ...state,
            toastQueue: [...state.toastQueue, "Reached area boundary. Navigation impossible."]
        };
    }

    const targetRoom = session.grid[newY][newX];
    if (targetRoom === 'WALL') {
        return {
            ...state,
            toastQueue: [...state.toastQueue, "A massive obstruction blocks the path."]
        };
    }

    const isAlreadyVisited = session.visited[newY][newX];
    const cost = isAlreadyVisited ? -1 : (targetRoom === 'BOSS' ? dungeon.bossEnergy : dungeon.moveEnergy);

    const party = state.knownMercenaries.filter(m => session.partyIds.includes(m.id));
    if (cost > 0 && party.some(m => (m.expeditionEnergy || 0) < cost)) {
        return { ...state, logs: [`Your squad is too exhausted to move further.`, ...state.logs] };
    }

    if (targetRoom === 'BOSS' && session.isBossLocked && !session.hasKey) {
        return { ...state, logs: [`The Boss chamber is sealed. You need a key.`, ...state.logs] };
    }

    let updatedMercs = state.knownMercenaries.map(m => {
        if (session.partyIds.includes(m.id)) {
            let nextEnergy = Math.max(0, (m.expeditionEnergy || 0) - cost);
            let nextHp = m.currentHp;
            if (targetRoom === 'TRAP' && !isAlreadyVisited) nextHp = Math.max(0, m.currentHp - 25);
            return { ...m, expeditionEnergy: nextEnergy, currentHp: nextHp };
        }
        return m;
    });

    // Check for Squad Wipeout after Trap
    const isWipedOut = targetRoom === 'TRAP' && !isAlreadyVisited && 
                       updatedMercs.filter(m => session.partyIds.includes(m.id)).every(m => m.currentHp <= 0);

    if (isWipedOut) {
        // Force retreat if all members are neutralized
        const wipedState = { ...state, knownMercenaries: updatedMercs, activeManualDungeon: session };
        return handleRetreatManualDungeon(wipedState);
    }

    const newVisited = [...session.visited.map(row => [...row])];
    newVisited[newY][newX] = true;

    let extraGold = 0;
    let newGrid = [...session.grid.map(row => [...row])];
    let logMsg = '';
    let encounterStatus: ManualDungeonSession['encounterStatus'] = 'NONE';

    if (targetRoom === 'GOLD' && !isAlreadyVisited) {
        extraGold = (dungeon.tier || 1) * 50;
        newGrid[newY][newX] = 'EMPTY';
        logMsg = `Treasury cache secured. (+${extraGold} G)`;
    } else if (targetRoom === 'TRAP' && !isAlreadyVisited) {
        logMsg = `AMBUSH: Traps detected. Squad took heavy damage. (-25 HP)`;
    } else if (targetRoom === 'KEY' && !isAlreadyVisited) {
        logMsg = `Chamber key recovered.`;
        newGrid[newY][newX] = 'EMPTY';
    } else if (targetRoom === 'BOSS' && !session.isBossDefeated) {
        encounterStatus = 'ENCOUNTERED';
        logMsg = `CRITICAL ALERT: ${session.bossEntity?.name} identified. Defense systems active.`;
    }

    const newPathHistory = [{ x: newX, y: newY }, ...session.pathHistory].slice(0, 50);

    return {
        ...state,
        knownMercenaries: updatedMercs,
        activeManualDungeon: {
            ...session,
            grid: newGrid,
            playerPos: { x: newX, y: newY },
            pathHistory: newPathHistory,
            visited: newVisited,
            hasKey: targetRoom === 'KEY' ? true : session.hasKey,
            encounterStatus,
            goldCollected: session.goldCollected + extraGold
        },
        logs: logMsg ? [logMsg, ...state.logs] : state.logs
    };
};

export const handleStartCombatManual = (state: GameState): GameState => {
    if (!state.activeManualDungeon) return state;
    return {
        ...state,
        activeManualDungeon: {
            ...state.activeManualDungeon,
            encounterStatus: 'BATTLE'
        }
    };
};

export const handleResolveCombatManual = (state: GameState, payload: { win: boolean, flee: boolean, finalParty: any[] }): GameState => {
    const session = state.activeManualDungeon;
    if (!session) return state;

    let logMsg = '';

    // XP Distribution Logic on Victory
    const livingMembers = payload.finalParty.filter(p => p.currentHp > 0);
    const xpPerMember = (payload.win && session.bossEntity && livingMembers.length > 0) 
        ? Math.floor(session.bossEntity.rewardXp / livingMembers.length) 
        : 0;

    if (payload.win && xpPerMember > 0) {
        logMsg = `VICTORY: ${session.bossEntity?.name} defeated! Living squad members gained ${xpPerMember} XP.`;
    }

    // Sync stats from combat and distribute XP
    const newKnownMercenaries = state.knownMercenaries.map(m => {
        const combatant = payload.finalParty.find(p => p.id === m.id);
        if (combatant) {
            let nextXp = m.currentXp;
            let nextLevel = m.level;
            let nextMaxHp = m.maxHp;
            let nextMaxMp = m.maxMp;
            let nextCurrentHp = combatant.currentHp;

            if (payload.win && combatant.currentHp > 0) {
                nextXp += xpPerMember;
                while (nextXp >= m.xpToNextLevel) {
                    nextXp -= m.xpToNextLevel;
                    nextLevel++;
                    // Basic level up vitality refresh
                    const merged = mergePrimaryStats(m.stats, m.allocatedStats);
                    nextMaxHp = calculateMaxHp(merged, nextLevel);
                    nextMaxMp = calculateMaxMp(merged, nextLevel);
                    nextCurrentHp = nextMaxHp; // Heal on level up
                    logMsg += ` ${m.name} reached Level ${nextLevel}!`;
                }
            }

            return { 
                ...m, 
                currentHp: nextCurrentHp, 
                currentMp: combatant.currentMp,
                currentXp: nextXp,
                level: nextLevel,
                maxHp: nextMaxHp,
                maxMp: nextMaxMp,
                xpToNextLevel: nextLevel * 100
            };
        }
        return m;
    });

    let nextStatus: ManualDungeonSession['encounterStatus'] = payload.win ? 'VICTORY' : (payload.flee ? 'NONE' : 'DEFEAT');
    let nextPos = session.playerPos;
    let nextHistory = session.pathHistory;

    // Back off to previous safe tile on flee
    if (payload.flee) {
        nextPos = session.pathHistory[1] || session.playerPos;
        nextHistory = session.pathHistory.slice(1);
    }

    return {
        ...state,
        knownMercenaries: newKnownMercenaries,
        activeManualDungeon: {
            ...session,
            playerPos: nextPos,
            pathHistory: nextHistory,
            encounterStatus: nextStatus,
            isBossDefeated: payload.win || session.isBossDefeated
        },
        logs: payload.flee ? ['TACTICAL WITHDRAWAL: Back to safe zone.', ...state.logs] : (logMsg ? [logMsg, ...state.logs] : state.logs)
    };
};

export const handleFinishManualDungeon = (state: GameState): GameState => {
    const session = state.activeManualDungeon;
    if (!session) return state;

    const dummyExpId = `manual_clear_${Date.now()}`;
    const tempState: GameState = {
        ...state,
        activeExpeditions: [{
            id: dummyExpId, dungeonId: session.dungeonId, partyIds: session.partyIds,
            startTime: Date.now(), endTime: Date.now(), status: 'COMPLETED' as const
        }]
    };

    const finalState = handleClaimExpedition(tempState, { expeditionId: dummyExpId, rescuedNpcId: session.rescuedNpcId });
    const totalManualGold = session.goldCollected;

    // Check if any mercenary returned with 0 HP and set INJURED status
    const checkedMercenaries = finalState.knownMercenaries.map(m => {
        if (session.partyIds.includes(m.id) && m.currentHp < 1) {
            return { 
                ...m, 
                status: 'INJURED' as const, 
                recoveryUntilDay: finalState.stats.day + Math.floor(Math.random() * 2) + 1 
            };
        }
        return m;
    });

    return { 
        ...finalState, 
        knownMercenaries: checkedMercenaries,
        stats: {
            ...finalState.stats,
            gold: finalState.stats.gold + totalManualGold,
            dailyFinancials: { ...finalState.stats.dailyFinancials, incomeDungeon: finalState.stats.dailyFinancials.incomeDungeon + totalManualGold }
        },
        activeManualDungeon: null, 
        showManualDungeonOverlay: false 
    };
};

export const handleRetreatManualDungeon = (state: GameState): GameState => {
    const session = state.activeManualDungeon;
    if (!session) return state;

    const isDefeat = session.encounterStatus === 'DEFEAT' || 
                    state.knownMercenaries.filter(m => session.partyIds.includes(m.id)).every(m => m.currentHp <= 0);

    const dungeon = DUNGEONS.find(d => d.id === session.dungeonId);

    const mercResults: DungeonResult['mercenaryResults'] = [];
    const updatedMercs = state.knownMercenaries.map(m => {
        if (session.partyIds.includes(m.id)) {
            let nextStatus: any = 'HIRED';
            let statusChange: 'NONE' | 'INJURED' | 'DEAD' = 'NONE';
            let recoveryUntilDay: number | undefined = undefined;

            // If they have 0 HP, they are definitely injured
            const isUnconscious = m.currentHp < 1;

            if (isDefeat) {
                const roll = Math.random();
                if (roll < 0.15) { 
                    nextStatus = 'DEAD'; 
                    statusChange = 'DEAD'; 
                }
                else {
                    nextStatus = 'INJURED'; 
                    statusChange = 'INJURED'; 
                    recoveryUntilDay = state.stats.day + Math.floor(Math.random() * 3) + 1;
                }
            } else if (isUnconscious) {
                nextStatus = 'INJURED'; 
                statusChange = 'INJURED'; 
                recoveryUntilDay = state.stats.day + Math.floor(Math.random() * 2) + 1;
            }

            mercResults.push({
                id: m.id, name: m.name, job: m.job, levelBefore: m.level, levelAfter: m.level,
                xpGained: 0, currentXp: m.currentXp, xpToNext: m.xpToNextLevel, statusChange
            });

            return { 
                ...m, 
                status: nextStatus, 
                assignedExpeditionId: undefined,
                recoveryUntilDay 
            };
        }
        return m;
    });

    return {
        ...state,
        knownMercenaries: updatedMercs,
        dungeonResult: isDefeat ? {
            dungeonName: dungeon?.name || 'Unknown',
            rewards: [],
            goldGained: 0,
            mercenaryResults: mercResults,
            isDefeat: true
        } : state.dungeonResult,
        activeManualDungeon: null,
        showManualDungeonOverlay: false,
        logs: [isDefeat ? 'CRITICAL FAILURE: The squad has been neutralized.' : 'The squad retreated to safety.', ...state.logs]
    };
};

export const handleRescueNPC = (state: GameState, payload: { npcId: string }): GameState => {
    const currentSession = state.activeManualDungeon;
    if (!currentSession) return state;

    let newGrid = [...currentSession.grid.map(row => [...row])];
    newGrid[currentSession.playerPos.y][currentSession.playerPos.x] = 'EMPTY';

    return {
        ...state,
        activeManualDungeon: { ...currentSession, grid: newGrid, npcFound: true, rescuedNpcId: payload.npcId },
        logs: [`Rescue initiated for survivor. Secure the area for extraction.`, ...state.logs]
    };
};

