        let bgColor = 'bg-stone-950/40';

        if (equippedItem) {
            switch (equippedItem.rarity) {
                case 'Common': borderColor = isSelected ? 'border-amber-400' : 'border-stone-500'; break;
                case 'Uncommon': borderColor = isSelected ? 'border-amber-400' : 'border-emerald-600'; break;
                case 'Rare': borderColor = isSelected ? 'border-amber-400' : 'border-blue-500'; break;
                case 'Epic': borderColor = isSelected ? 'border-amber-400' : 'border-purple-500'; break;
                case 'Legendary': borderColor = isSelected ? 'border-amber-400' : 'border-amber-500'; break;
            }
            bgColor = 'bg-stone-800/60';
        }

        let imageUrl = '';
        if (equippedItem) {
            imageUrl = equippedItem.image ? getAssetUrl(equippedItem.image) : (equippedItem.recipeId ? getAssetUrl(`${equippedItem.recipeId}.png`) : getAssetUrl(`${equippedItem.id.split('_')[0]}.png`));
        }

        return (
            <div 
                className={`absolute w-10 h-10 md:w-14 md:h-14 rounded-xl border-2 backdrop-blur-md ${borderColor} ${bgColor} flex items-center justify-center shadow-lg transition-all z-20 group ${style} ${isSelected ? 'ring-4 ring-amber-500/30 scale-110' : 'hover:scale-105'} cursor-pointer`}
                onClick={() => onSlotClick(isSelected ? null : slot)}
            >
                {equippedItem ? (
                    <img src={imageUrl} className="w-7 h-7 md:w-10 md:h-10 object-contain drop-shadow-md" />
                ) : (
                    <div className="text-stone-600/80 scale-75 md:scale-100">{icon}</div>
                )}
                {equippedItem && !isReadOnly && (
                    <button
                        onClick={(e) => { e.stopPropagation(); onUnequip(slot); }}
                        className="absolute -top-2 -right-2 bg-red-600 rounded-full p-1 opacity-0 group-hover:opacity-100 transition-opacity text-white shadow-lg"
                    >
                        <X className="w-3 h-3" />
                    </button>
                )}
            </div>
        );
    };

    return (
        <div className="w-[42%] h-full relative bg-stone-900/40 flex flex-col overflow-hidden border-r border-white/5">
            <div className="p-3 md:p-6 flex flex-col gap-0.5 md:gap-1 shrink-0 bg-stone-950/40 border-b border-white/5 backdrop-blur-md z-30">
                <h2 className="text-xs md:text-2xl font-black text-stone-100 font-serif truncate leading-none">{mercenary.name}</h2>
                <div className="flex justify-between items-end">
                    <div className="flex wrap items-center gap-1">
                        <span className="text-[6px] md:text-xs font-black text-amber-500 uppercase tracking-widest bg-amber-950/40 px-1 py-0.5 rounded border border-amber-900/20">{mercenary.job}</span>
                        <div className={`flex items-center gap-0.5 text-[8px] md:text-sm ${showAffinityGain ? 'text-pink-400 animate-pulse' : 'text-stone-500 font-bold'}`}>
                            <Heart className={`w-2.5 h-2.5 md:w-3.5 md:h-3.5 ${showAffinityGain ? 'fill-pink-500' : ''}`} />
                            <span>{mercenary.affinity}</span>
                        </div>
                    </div>
                    <div className="text-right">
                        <span className="text-[6px] md:text-[9px] text-stone-600 uppercase font-black tracking-tighter block leading-none">Power</span>
                        <div className="flex items-center gap-0.5 md:gap-1 text-[10px] md:text-xl font-mono font-black text-stone-300">
                            <Star className="w-2.5 h-2.5 md:w-4 md:h-4 text-amber-600 fill-amber-600" />
                            {nextCombatPower}
                        </div>
                    </div>
                </div>
            </div>

            <div className="flex-1 relative w-full flex items-center justify-center overflow-hidden min-h-0">
                <div className="relative h-[90%] w-full flex items-center justify-center pointer-events-none opacity-80">
                    <img 
                        src={mercenary.sprite ? getAssetUrl(mercenary.sprite) : getAssetUrl('adventurer_wanderer_01.png')}
                        className="h-full object-contain filter drop-shadow-[0_0_20px_rgba(0,0,0,0.5)]"
                    />
                </div>
                {renderSlot({ slot: "HEAD", icon: <Crown className="w-5 h-5" />, style: "top-[6%] left-1/2 -translate-x-1/2" })}
                {renderSlot({ slot: "BODY", icon: <Shirt className="w-5 h-5" />, style: "top-[26%] left-1/2 -translate-x-1/2" })}
                {renderSlot({ slot: "HANDS", icon: <Hand className="w-5 h-5" />, style: "top-[26%] left-[8%]" })}
                {renderSlot({ slot: "ACCESSORY", icon: <Sparkles className="w-5 h-5" />, style: "top-[26%] right-[8%]" })}
                {renderSlot({ slot: "MAIN_HAND", icon: <Sword className="w-5 h-5" />, style: "top-[48%] left-[4%]" })}
                {renderSlot({ slot: "OFF_HAND", icon: <Shield className="w-5 h-5" />, style: "top-[48%] right-[4%]" })}
                {renderSlot({ slot: "FEET", icon: <Footprints className="w-5 h-5" />, style: "bottom-[10%] left-1/2 -translate-x-1/2" })}
            </div>
        </div>
    );
};

const MercenaryStatsPanel = ({ 
    mercenary, 
    baseStats,
    finalStats, 
    localAllocated,
    equipmentStats,
    onSetLocalAllocated,
    isReadOnly
}: { 
    mercenary: Mercenary; 
    baseStats: DerivedStats;
    finalStats: DerivedStats; 
    localAllocated: PrimaryStats;
    equipmentStats: PrimaryStats;
    onSetLocalAllocated: (stats: PrimaryStats) => void;
    isReadOnly?: boolean;
}) => {
    const { actions } = useGame();
    const xpPercent = mercenary.xpToNextLevel > 0 ? Math.min(100, Math.max(0, (mercenary.currentXp / mercenary.xpToNextLevel) * 100)) : 0;
    const hpPercent = finalStats.maxHp > 0 ? (mercenary.currentHp / finalStats.maxHp) * 100 : 0;
    const mpPercent = finalStats.maxMp > 0 ? (mercenary.currentMp / finalStats.maxMp) * 100 : 0;

    const totalUsedLocal = Object.values(localAllocated).reduce((a, b) => a + b, 0);
    const totalPoints = (mercenary.level - 1) * 3;
    const availablePoints = Math.max(0, totalPoints - totalUsedLocal);
    const hasChanges = JSON.stringify(localAllocated) !== JSON.stringify(mercenary.allocatedStats);

    const renderStatRow = (icon: React.ReactNode, label: string, baseValue: number, nextValue: number, isPercent = false) => {
        const diff = nextValue - baseValue;
        const colorClass = diff > 0 ? 'text-emerald-400' : diff < 0 ? 'text-red-400' : 'text-stone-300';
        return (
            <div className="bg-stone-950/40 p-1.5 md:p-3 rounded-lg border border-white/5 flex justify-between items-center h-8 md:h-12">
                <span className="text-[7px] md:text-xs text-stone-500 font-black uppercase flex items-center gap-1.5 md:gap-2">
                    {icon} 
                    <span className="hidden md:inline">{label}</span>
                    <span className="md:hidden">
                        {label === 'Physical Atk' ? 'P.Atk' : 
                         label === 'Physical Def' ? 'P.Def' : 
                         label === 'Magical Atk' ? 'M.Atk' : 
                         label === 'Magical Def' ? 'M.Def' : 
                         label === 'Crit Rate' ? 'Crit' : 
                         label === 'Evasion' ? 'Eva' : label}
                    </span>
                </span>
                <div className="flex items-center gap-1 md:gap-2">
                    <span className={`font-mono text-[9px] md:text-base font-black ${colorClass}`}>
                        {isPercent ? nextValue.toFixed(1) : Math.round(nextValue)}{isPercent ? '%' : ''}
                    </span>
                    <StatDiff current={baseValue} next={nextValue} isPercent={isPercent} />
                </div>
            </div>
        );
    };

    const updateLocalStat = (key: keyof PrimaryStats, delta: number) => {
        const newVal = localAllocated[key] + delta;
        if (delta > 0 && availablePoints <= 0) return;
        if (delta < 0 && newVal < mercenary.allocatedStats[key]) return;
        onSetLocalAllocated({ ...localAllocated, [key]: newVal });
    };

    return (
        <div className="flex-1 overflow-y-auto custom-scrollbar p-3 md:p-6 flex flex-col gap-4 md:gap-6 min-h-0 bg-stone-900/10">
            <div className="bg-stone-950/40 p-2 md:p-5 rounded-xl border border-white/5 shadow-inner shrink-0">
                <div className="flex justify-between items-end mb-1 md:mb-2 leading-none">
                    <span className="text-amber-500 font-black font-mono text-[10px] md:text-lg uppercase tracking-tight">LV {mercenary.level}</span>
                    <span className="text-stone-500 text-[8px] md:text-sm font-mono font-bold">{mercenary.currentXp} / {mercenary.xpToNextLevel} XP</span>
                </div>
                <div className="w-full h-1 md:h-2 bg-stone-900 rounded-full overflow-hidden border border-white/5">
                    <div className="h-full bg-gradient-to-r from-amber-800 to-amber-500 transition-all duration-700" style={{ width: `${xpPercent}%` }}></div>
                </div>
            </div>

            <div className="bg-stone-950/60 rounded-xl border border-stone-800 p-3 md:p-6 shrink-0 relative overflow-hidden">
                <div className="flex justify-between items-center mb-3 md:mb-4 px-1">
                    <h4 className="text-[8px] md:text-xs font-black text-stone-500 uppercase tracking-widest flex items-center gap-1.5 md:gap-2"><Star className="w-3 h-3 text-amber-600" /> Attributes</h4>
                    {!isReadOnly && availablePoints > 0 && (
                         <span className="text-[8px] md:text-xs font-black text-amber-400 px-2 md:px-3 py-0.5 md:py-1 bg-amber-900/30 border border-amber-500/30 rounded-full animate-pulse">POINTS: {availablePoints}</span>
                    )}
                </div>
                <div className="grid grid-cols-5 gap-1.5 md:gap-4">
                    {[
                        { label: 'STR', key: 'str' as const, color: 'text-orange-400' },
                        { label: 'INT', key: 'int' as const, color: 'text-blue-400' },
                        { label: 'DEX', key: 'dex' as const, color: 'text-emerald-400' },
                        { label: 'VIT', key: 'vit' as const, color: 'text-red-400' },
                        { label: 'LUK', key: 'luk' as const, color: 'text-pink-400' }
                    ].map((stat) => {
                        const equipBonus = equipmentStats[stat.key] || 0;
                        const basePlusAlloc = mercenary.stats[stat.key] + localAllocated[stat.key];
                        const totalValue = basePlusAlloc + equipBonus;
                        const isAllocatedModified = localAllocated[stat.key] > mercenary.allocatedStats[stat.key];

                        return (
                            <div key={stat.key} className="flex flex-col gap-1 md:gap-1.5">
                                <div className={`bg-stone-900/80 border ${isAllocatedModified ? 'border-amber-500 shadow-glow-sm' : 'border-stone-800'} p-1 md:p-2 rounded-lg flex flex-col items-center justify-center h-14 md:h-24 transition-all relative`}>
                                    <span className={`text-[6px] md:text-[10px] font-black ${stat.color} mb-0.5`}>{stat.label}</span>
                                    <span className={`text-[10px] md:text-xl font-mono font-black ${isAllocatedModified ? 'text-amber-400' : 'text-stone-400'}`}>{totalValue}</span>
                                    {equipBonus > 0 && (
                                        <span className="text-[6px] md:text-[9px] font-bold text-emerald-400 leading-none mt-0.5">+{equipBonus}</span>
                                    )}
                                </div>
                                {!isReadOnly && (
                                    <div className="flex flex-col gap-0.5 md:gap-1">
                                        <button onClick={() => updateLocalStat(stat.key, 1)} disabled={availablePoints <= 0} className="w-full h-4 md:h-8 bg-stone-800 hover:bg-amber-600 text-stone-500 hover:text-white rounded transition-all disabled:opacity-0 flex items-center justify-center shadow-sm"><Plus className="w-3 h-3" /></button>
                                        <button onClick={() => updateLocalStat(stat.key, -1)} disabled={localAllocated[stat.key] <= mercenary.allocatedStats[stat.key]} className="w-full h-3 md:h-6 bg-stone-950 hover:bg-red-700 text-stone-700 hover:text-white rounded transition-all disabled:opacity-0 flex items-center justify-center"><Minus className="w-2.5 h-2.5" /></button>
                                    </div>
                                )}
                            </div>
                        );
                    })}
                </div>
                {!isReadOnly && hasChanges && (
                    <div className="mt-4 md:mt-6 flex gap-2 md:gap-3 animate-in slide-in-from-top-2">
                        <button onClick={() => onSetLocalAllocated({ ...mercenary.allocatedStats })} className="flex-1 py-2 bg-stone-800 text-stone-500 text-[10px] font-black rounded-lg transition-all uppercase">Discard</button>
                        <button onClick={() => actions.updateMercenaryStats(mercenary.id, localAllocated)} className="flex-[2] py-2 bg-amber-700 text-white text-[10px] font-black rounded-lg shadow-lg transition-all uppercase">Confirm</button>
                    </div>
                )}
            </div>

            {/* Techniques & Skills Section */}
            <div className="bg-stone-950/60 rounded-xl border border-stone-800 p-3 md:p-6 shrink-0">
                <h4 className="text-[8px] md:text-xs font-black text-stone-500 uppercase tracking-widest flex items-center gap-1.5 md:gap-2 mb-4 px-1"><Sparkles className="w-3 h-3 text-amber-500" /> Techniques & Skills</h4>
                <div className="space-y-2">
                    {mercenary.skillIds && mercenary.skillIds.length > 0 ? (
                        mercenary.skillIds.map(id => {
                            const skill = SKILLS[id];
                            return (
                                <div key={id} className="bg-stone-900/80 border border-stone-800 rounded-xl p-3 flex flex-col gap-1.5">
                                    <div className="flex justify-between items-center">
                                        <div className="flex items-center gap-2">
                                            <div className="p-1 bg-amber-900/30 rounded border border-amber-700/30">
                                                <Sword className="w-3 h-3 text-amber-500" />
                                            </div>
                                            <span className="font-black text-[10px] md:text-sm text-stone-100 uppercase">{skill.name}</span>
                                        </div>
                                        <div className="flex items-center gap-2">
                                            <span className="text-[7px] md:text-[9px] font-black text-blue-400 bg-blue-900/20 px-2 py-0.5 rounded border border-blue-800/30 uppercase">{skill.mpCost} MP</span>
                                            <span className="text-[7px] md:text-[9px] font-black text-amber-500 bg-amber-900/20 px-2 py-0.5 rounded border border-amber-800/30 uppercase">{Math.round(skill.multiplier * 100)}% {skill.type === 'PHYSICAL' ? 'P.ATK' : 'M.ATK'}</span>
                                        </div>
                                    </div>
                                    <p className="text-[8px] md:text-xs text-stone-500 italic leading-tight pl-7">"{skill.description}"</p>
                                </div>
                            );
                        })
                    ) : (
                        <div className="py-4 text-center border-2 border-dashed border-stone-800 rounded-xl">
                            <span className="text-[8px] md:text-xs text-stone-600 font-bold uppercase">No techniques learned</span>
                        </div>
                    )}
                </div>
            </div>

            <div className="grid grid-cols-2 gap-2 md:gap-6 shrink-0">
                <div className="bg-stone-950/40 p-2 md:p-5 rounded-xl border border-white/5 flex items-center gap-2 md:gap-4 shadow-sm">
                    <div className="p-1.5 md:p-3 bg-red-950/40 rounded-lg text-red-500 border border-red-900/30"><Heart className="w-4 h-4 md:w-7 md:h-7" /></div>
                    <div className="flex-1 min-w-0">
                        <div className="flex justify-between text-[7px] md:text-xs text-stone-500 font-black mb-0.5 md:mb-1"><span>HP</span><span className="text-stone-300 font-mono">{mercenary.currentHp}/{finalStats.maxHp}</span></div>
                        <div className="w-full h-1 md:h-2 bg-stone-900 rounded-full overflow-hidden shadow-inner"><div className="h-full bg-red-600 transition-all duration-500" style={{ width: `${hpPercent}%` }}></div></div>
                    </div>
                </div>
                <div className="bg-stone-950/40 p-2 md:p-5 rounded-xl border border-white/5 flex items-center gap-2 md:gap-4 shadow-sm">
                    <div className="p-1.5 md:p-3 bg-blue-950/40 rounded-lg text-blue-500 border border-blue-900/30"><Activity className="w-4 h-4 md:w-7 md:h-7" /></div>
                    <div className="flex-1 min-w-0">
                        <div className="flex justify-between text-[7px] md:text-xs text-stone-500 font-black mb-0.5 md:mb-1"><span>MP</span><span className="text-stone-300 font-mono">{mercenary.currentMp}/{finalStats.maxMp}</span></div>
                        <div className="w-full h-1 md:h-2 bg-stone-900 rounded-full overflow-hidden shadow-inner"><div className="h-full bg-blue-600 transition-all duration-500" style={{ width: `${mpPercent}%` }}></div></div>
                    </div>
                </div>
            </div>

            <div className="space-y-2 md:space-y-3 pb-6 shrink-0">
                <h4 className="text-[8px] md:text-xs font-black text-stone-500 uppercase tracking-widest flex items-center gap-1.5 px-1"><Sword className="w-3 h-3" /> Battle Performance</h4>
                <div className="grid grid-cols-2 gap-1.5 md:gap-4">
                    {renderStatRow(<Sword className="w-3 h-3 md:w-4 md:h-4 text-orange-500" />, 'Physical Atk', baseStats.physicalAttack, finalStats.physicalAttack)}
                    {renderStatRow(<Shield className="w-3 h-3 md:w-4 md:h-4 text-blue-500" />, 'Physical Def', baseStats.physicalDefense, finalStats.physicalDefense)}
                    {renderStatRow(<Zap className="w-3 h-3 md:w-4 md:h-4 text-blue-400" />, 'Magical Atk', baseStats.magicalAttack, finalStats.magicalAttack)}
                    {renderStatRow(<Brain className="w-3 h-3 md:w-4 md:h-4 text-purple-400" />, 'Magical Def', baseStats.magicalDefense, finalStats.magicalDefense)}
                    {renderStatRow(<Target className="w-3 h-3 md:w-4 md:h-4 text-red-500" />, 'Crit Rate', baseStats.critChance, finalStats.critChance, true)}
                    {renderStatRow(<Wind className="w-3 h-3 md:w-4 md:h-4 text-emerald-400" />, 'Evasion', baseStats.evasion, finalStats.evasion)}
                </div>
            </div>
        </div>
    );
};

const EquipmentInventoryList = ({ 
    inventory, 
    selectedItemId,
    onSelect,
    onEquip,
    selectedSlotFilter,
    mercenary,
    isReadOnly
}: { 
    inventory: InventoryItem[]; 
    selectedItemId: string | null;
    onSelect: (itemId: string) => void;
    onEquip: (itemId: string) => void;
    selectedSlotFilter: EquipmentSlotType | null;
    mercenary: Mercenary;
    isReadOnly?: boolean;
}) => {
    // CURRENT CHANGE: Exclude equipment bonuses from requirement checks.
    // Standard CP calculation uses merged stats, but we want pure attributes here.
    const pureMercStats = useMemo(() => {
        return mergePrimaryStats(mercenary.stats, mercenary.allocatedStats);
    }, [mercenary.stats, mercenary.allocatedStats]);

    const displayInventory = useMemo(() => {
        return selectedSlotFilter 
            ? inventory.filter(item => item.equipmentData?.slotType === selectedSlotFilter)
            : inventory;
    }, [inventory, selectedSlotFilter]);

    const getQualityLabel = (q: number): string => {
        if (q >= 110) return 'MASTERWORK';
        if (q >= 100) return 'PRISTINE';
        if (q >= 90) return 'SUPERIOR';
        if (q >= 80) return 'FINE';
        if (q >= 70) return 'STANDARD';
        if (q >= 60) return 'RUSTIC';
        return 'CRUDE';
    };

    return (
        <div className="flex-1 flex flex-col min-h-0 bg-stone-950/40">
            <div className="p-3 md:p-6 bg-stone-900/60 border-b border-white/5 flex justify-between items-center shrink-0 z-10 backdrop-blur-md">
                <h3 className="text-[9px] md:text-xs font-black text-stone-400 uppercase tracking-widest flex items-center gap-2">
                    <Box className="w-4 h-4 text-amber-600" /> 
                    <span>{selectedSlotFilter ? `Filtering: ${selectedSlotFilter}` : 'Available Gear'}</span>
                </h3>
                <span className="text-[8px] md:text-xs text-stone-600 font-mono">{displayInventory.length} ITEMS</span>
            </div>

            <div className="flex-1 overflow-y-auto custom-scrollbar p-3 md:p-6 space-y-2 md:space-y-3">
                {displayInventory.length === 0 ? (
                    <div className="h-full flex flex-col items-center justify-center text-stone-800 italic p-12 text-center">
                        <Box className="w-12 h-12 opacity-10 mb-2" />
                        <p className="text-xs">No suitable gear found.</p>
                    </div>
                ) : (
                    displayInventory.map(item => {
                        if (!item.equipmentData) return null;
                        const isSelected = selectedItemId === item.id;
                        const reqs = item.equipmentData.equipRequirements || {};

                        // Use pureMercStats instead of totalMercStats to ignore bonuses from current gear
                        const failedStats = Object.entries(reqs).filter(([stat, val]) => 
                            pureMercStats[stat as keyof PrimaryStats] < (val as number)
                        );

                        const canEquip = failedStats.length === 0;
                        const rarityClasses = getRarityClasses(item.equipmentData.rarity);
                        let imageUrl = item.equipmentData.image ? getAssetUrl(item.equipmentData.image) : (item.equipmentData.recipeId ? getAssetUrl(`${item.equipmentData.recipeId}.png`) : getAssetUrl(`${item.id.split('_')[0]}.png`));

                        return (
                            <div 
                                key={item.id}
                                onClick={() => !isSelected && onSelect(item.id)}
                                className={`flex flex-col gap-2 p-3 md:p-5 rounded-xl border transition-all ${isSelected ? 'border-amber-500 bg-stone-900/80 shadow-inner' : 'border-stone-800 bg-stone-900/30'} cursor-pointer group ${!canEquip ? 'opacity-60' : ''}`}
                            >
                                <div className="flex items-center gap-3 md:gap-4">
                                    <div className={`w-10 h-10 md:w-16 md:h-16 bg-stone-950 rounded-lg border-2 flex items-center justify-center shrink-0 ${rarityClasses}`}>
                                        <img src={imageUrl} className="w-8 h-8 md:w-12 md:h-12 object-contain" />
                                    </div>
                                    <div className="flex-1 min-w-0">
                                        <div className="text-[11px] md:text-lg font-black truncate text-stone-200">{item.name}</div>
                                        <div className="flex flex-wrap items-center gap-2 mt-1">
                                            <span className={`text-[7px] md:text-[9px] px-1.5 py-0.5 rounded font-black uppercase border leading-none ${rarityClasses}`}>
                                                {item.equipmentData.rarity}
                                            </span>
                                            <span className="text-[7px] md:text-[9px] text-stone-600 font-mono font-bold">LV.{item.equipmentData.quality >= 100 ? 'EX' : 'ST'}</span>
                                        </div>
                                    </div>
                                    {!isReadOnly && isSelected && canEquip && (
                                        <button 
                                            onClick={(e) => { e.stopPropagation(); onEquip(item.id); }}
                                            className="shrink-0 px-3 md:px-8 py-1.5 md:py-3 bg-amber-700 hover:bg-amber-600 text-white text-[9px] md:text-xs font-black uppercase rounded shadow-lg transition-all"
                                        >
                                            Equip
                                        </button>
                                    )}
                                </div>
                                {!canEquip && isSelected && (
                                    <div className="bg-red-950/20 border border-red-900/30 rounded-lg p-2 flex items-center gap-2 text-[8px] md:text-[10px] text-red-400 font-bold uppercase tracking-tight">
                                        <AlertCircle className="w-3 h-3 shrink-0" />
                                        Requirements not met: {failedStats.map(([s,v]) => `${s.toUpperCase()} ${v}`).join(', ')}
                                    </div>
                                )}
                                <div className="flex justify-between items-center border-t border-white/5 pt-2">
                                    <div className="flex items-center gap-2 text-[8px] md:text-xs text-stone-600 font-bold">
                                        <ShieldAlert className="w-3 h-3" />
                                        DUR: {item.equipmentData.durability}/{item.equipmentData.maxDurability}
                                    </div>
                                    <div className="flex items-center gap-2">
                                        <span className="text-[7px] md:text-[9px] text-amber-600 font-black uppercase tracking-tighter bg-amber-950/20 px-1.5 py-0.5 rounded border border-amber-900/20">
                                            {getQualityLabel(item.equipmentData.quality)}
                                        </span>
                                    </div>
                                </div>
                            </div>
                        );
                    })
                )}
            </div>
        </div>
    );
};

export const MercenaryDetailModal: React.FC<MercenaryDetailModalProps> = ({ mercenary, onClose, onUnequip, isReadOnly = false }) => {
    const { state, actions } = useGame();
    const [selectedSlot, setSelectedSlot] = useState<EquipmentSlotType | null>(null);
    const [selectedInventoryItemId, setSelectedInventoryItemId] = useState<string | null>(null);
    const [activeTab, setActiveTab] = useState<'STATS' | 'STORAGE'>('STATS');
    const [localAllocated, setLocalAllocated] = useState<PrimaryStats>({ str: 0, vit: 0, dex: 0, int: 0, luk: 0 });

    useEffect(() => {
        if (mercenary) {
            setSelectedSlot(null);
            setSelectedInventoryItemId(null);
            setLocalAllocated({ ...mercenary.allocatedStats });
            setActiveTab('STATS');
        }
    }, [mercenary?.id]);

    if (!mercenary) return null;

    // --- Core Stat Logic Sync ---
    const currentEqPrimaryStats = useMemo(() => {
        return (Object.values(mercenary.equipment).filter(Boolean) as Equipment[]).reduce((acc: PrimaryStats, eq: Equipment) => ({
            str: acc.str + (eq.stats.str || 0),
            vit: acc.vit + (eq.stats.vit || 0),
            dex: acc.dex + (eq.stats.dex || 0),
            int: acc.int + (eq.stats.int || 0),
            luk: acc.luk + (eq.stats.luk || 0),
        }), { str: 0, vit: 0, dex: 0, int: 0, luk: 0 });
    }, [mercenary.equipment]);

    const mergedPrimary = mergePrimaryStats(mercenary.stats, localAllocated, currentEqPrimaryStats);
    const baseDerived = calculateDerivedStats(mergedPrimary, mercenary.level);
    const currentEquipmentStats = (Object.values(mercenary.equipment) as (Equipment | null)[]).map(eq => eq?.stats).filter(Boolean);
    const currentStats = applyEquipmentBonuses(baseDerived, currentEquipmentStats as any);
    const currentAttackType = mergedPrimary.int > mergedPrimary.str ? 'MAGICAL' : 'PHYSICAL';
    const currentCombatPower = calculateCombatPower(currentStats, mercenary.job, currentAttackType);

    // --- Preview Logic Sync ---
    let previewStats: DerivedStats | null = null;
    let previewCombatPower: number | null = null;
    if (selectedInventoryItemId) {
        const item = state.inventory.find(i => i.id === selectedInventoryItemId)?.equipmentData;
        if (item) {
            const previewEq = { ...mercenary.equipment };
            if (item.slotType === 'MAIN_HAND' && item.isTwoHanded) previewEq.OFF_HAND = null;
            else if (item.slotType === 'OFF_HAND' && previewEq.MAIN_HAND?.isTwoHanded) previewEq.MAIN_HAND = null;
            previewEq[item.slotType] = item;

            const previewEqPrimary = (Object.values(previewEq).filter(Boolean) as Equipment[]).reduce((acc: PrimaryStats, eq: Equipment) => ({
                str: acc.str + (eq.stats.str || 0),
                vit: acc.vit + (eq.stats.vit || 0),
                dex: acc.dex + (eq.stats.dex || 0),
                int: acc.int + (eq.stats.int || 0),
                luk: acc.luk + (eq.stats.luk || 0),
            }), { str: 0, vit: 0, dex: 0, int: 0, luk: 0 });

            const previewMerged = mergePrimaryStats(mercenary.stats, localAllocated, previewEqPrimary);
            const previewBase = calculateDerivedStats(previewMerged, mercenary.level);
            previewStats = applyEquipmentBonuses(previewBase, (Object.values(previewEq) as (Equipment | null)[]).map(e => e?.stats).filter(Boolean) as any);
            previewCombatPower = calculateCombatPower(previewStats, mercenary.job, previewMerged.int > previewMerged.str ? 'MAGICAL' : 'PHYSICAL');
        }
    }

    const effectiveFinalStats = previewStats || currentStats;
    const effectiveCombatPower = previewCombatPower !== null ? previewCombatPower : currentCombatPower;

    return (
        <div className="fixed inset-0 z-[1000] flex items-center justify-center bg-black/95 backdrop-blur-2xl p-2 md:p-6 py-[15dvh] md:py-6 animate-in fade-in duration-300 overflow-hidden">
            <button 
                onClick={onClose} 
                className="fixed top-4 right-4 z-[1050] p-1.5 md:p-3 bg-red-900/30 hover:bg-red-600 rounded-full text-red-500 hover:text-white border border-red-500/30 transition-all shadow-2xl backdrop-blur-md active:scale-90"
            >
                <X className="w-4 h-4 md:w-6 md:h-6" />
            </button>

            <div className="w-full h-full md:max-w-7xl md:h-[90dvh] bg-stone-950 border border-white/10 rounded-2xl md:rounded-[2rem] shadow-2xl flex flex-row overflow-hidden relative ring-1 ring-white/10">
                <MercenaryPaperDoll 
                    mercenary={mercenary} 
                    baseCombatPower={currentCombatPower}
                    nextCombatPower={effectiveCombatPower} 
                    showAffinityGain={false} 
                    onUnequip={(slot) => onUnequip(mercenary.id, slot)} 
                    onSlotClick={(s) => { setSelectedSlot(s); if(s) setActiveTab('STORAGE'); }} 
                    selectedSlot={selectedSlot} 
                    isReadOnly={isReadOnly}
                />

                <div className="flex-1 bg-stone-900/30 flex flex-col h-full overflow-hidden">
                    <div className="flex border-b border-white/5 bg-stone-950/80 shrink-0 z-20 backdrop-blur-3xl pr-16 md:pr-0">
                        <button 
                            onClick={() => setActiveTab('STATS')}
                            className={`flex-1 py-3 md:py-6 text-[10px] md:text-sm font-black uppercase tracking-widest flex items-center justify-center gap-1.5 md:gap-3 transition-all whitespace-nowrap ${activeTab === 'STATS' ? 'text-amber-400 bg-stone-900/60 border-b-2 border-amber-500' : 'text-stone-600 hover:text-stone-300'}`}
                        >
                            <Activity className="w-3.5 h-3.5 md:w-5 md:h-5" /> <span>Stats</span>
                        </button>
                        <button 
                            onClick={() => setActiveTab('STORAGE')}
                            className={`flex-1 py-3 md:py-6 text-[10px] md:text-sm font-black uppercase tracking-widest flex items-center justify-center gap-1.5 md:gap-3 transition-all whitespace-nowrap ${activeTab === 'STORAGE' ? 'text-amber-400 bg-stone-900/60 border-b-2 border-amber-500' : 'text-stone-600 hover:text-stone-300'}`}
                        >
                            <Box className="w-3.5 h-3.5 md:w-5 md:h-5" /> <span>Storage</span>
                        </button>
                    </div>

                    <div className="flex-1 flex flex-col min-h-0 overflow-hidden px-safe pb-safe">
                        {activeTab === 'STATS' ? (
                            <MercenaryStatsPanel 
                                mercenary={mercenary} 
                                baseStats={currentStats}
                                finalStats={effectiveFinalStats} 
                                localAllocated={localAllocated}
                                equipmentStats={currentEqPrimaryStats}
                                onSetLocalAllocated={setLocalAllocated}
                                isReadOnly={isReadOnly}
                            />
                        ) : (
                            <EquipmentInventoryList 
                                inventory={state.inventory.filter(i => i.type === 'EQUIPMENT')} 
                                selectedItemId={selectedInventoryItemId} 
                                onSelect={setSelectedInventoryItemId} 
                                onEquip={(id) => { actions.equipItem(mercenary.id, id); setSelectedInventoryItemId(null); }} 
                                selectedSlotFilter={selectedSlot}
                                mercenary={mercenary}
                                isReadOnly={isReadOnly}
                            />
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
};

import React, { useEffect, useRef, useState, useMemo } from 'react';
import Phaser from 'phaser';
import { useGame } from '../../../context/GameContext';
import { DUNGEONS } from '../../../data/dungeons';
import DungeonScene from '../../../game/DungeonScene';
import DialogueBox from '../../DialogueBox';
import { 
    Key, Zap, LogOut, X, ChevronUp, ChevronDown, ChevronLeft, ChevronRight, Lock, Unlock, Target, Shield, Sword, Skull
} from 'lucide-react';
import ConfirmationModal from '../../modals/ConfirmationModal';
import { calculateCombatPower, calculateMercenaryPower } from '../../../utils/combatLogic';
import DungeonCombatView from './DungeonCombatView';

type CameraMode = 'LOCKED' | 'ADAPTIVE' | 'FREE';

const AssaultNavigator = () => {
    const { state, actions } = useGame();
    const session = state.activeManualDungeon;
    const gameRef = useRef<Phaser.Game | null>(null);
    const containerRef = useRef<HTMLDivElement>(null);
    const [isReady, setIsReady] = useState(false);
    const [showRetreatConfirm, setShowRetreatConfirm] = useState(false);
    const [cameraMode, setCameraMode] = useState<CameraMode>('LOCKED');

    const [isSquadStatusExpanded, setIsSquadStatusExpanded] = useState(true);
    const [lastDiscoveryMessage, setLastDiscoveryMessage] = useState<string>('');
    // 도주 직후 해당 칸에서만 포기 버튼을 노출하기 위한 상태
    const [showWithdrawAfterFlee, setShowWithdrawAfterFlee] = useState(false);

    const dungeon = session ? DUNGEONS.find(d => d.id === session.dungeonId) : null;
    const party = session ? state.knownMercenaries.filter(m => session.partyIds.includes(m.id)) : [];

    const isEncountered = session?.encounterStatus === 'ENCOUNTERED';
    const isBattle = session?.encounterStatus === 'BATTLE';
    const isVictory = session?.encounterStatus === 'VICTORY';
    const isDefeat = session?.encounterStatus === 'DEFEAT';

    const bossPower = useMemo(() => {
        if (!session?.bossEntity) return 0;
        return calculateCombatPower(session.bossEntity.stats, 'Fighter' as any, 'PHYSICAL');
    }, [session?.bossEntity]);

    const fleeChance = useMemo(() => {
        if (!session || !session.bossEntity) return 0;
        const partyCP = party.reduce((sum, m) => sum + calculateMercenaryPower(m), 0);
        return Math.max(5, Math.min(95, Math.round(50 + (partyCP - bossPower) / 5)));
    }, [session, party, bossPower]);

    const handleDpadMove = (dx: number, dy: number) => {
        if (isEncountered || isBattle) return;

        const nextX = (session?.playerPos.x || 0) + dx;
        const nextY = (session?.playerPos.y || 0) + dy;
        const gridW = dungeon?.gridWidth || 0;
        const gridH = dungeon?.gridHeight || 0;

        if (nextX < 0 || nextX >= gridW || nextY < 0 || nextY >= gridH) {
            setLastDiscoveryMessage("Navigation blocked: Area boundary reached.");
            return;
        }

        const targetRoom = session?.grid[nextY][nextX];
        if (targetRoom === 'WALL') {
            setLastDiscoveryMessage("Navigation blocked: Solid obstruction detected.");
            return;
        }

        // 이동 시 도주 직후 상태 및 차단 메시지 초기화
        setShowWithdrawAfterFlee(false);
        if (lastDiscoveryMessage.includes("blocked")) {
            setLastDiscoveryMessage("Moving to next sector...");
        }

        const scene = gameRef.current?.scene.getScene('DungeonScene') as DungeonScene;
        if (scene) scene.move(dx, dy);
    };

    const handleStartCombat = () => {
        actions.startCombatManual();
    };

    const handleFleeSuccess = (finalParty: any[]) => {
        actions.resolveCombatManual(false, true, finalParty);
        // 도주 성공 시 해당 위치에서만 포기 버튼 활성화
        setShowWithdrawAfterFlee(true);
        setLastDiscoveryMessage("TACTICAL WITHDRAWAL: Squad has returned to the previous safe position. Abandon the mission and return to the forge?");
    };

    useEffect(() => {
        const checkSize = () => {
            if (containerRef.current && containerRef.current.clientWidth > 0) setIsReady(true);
            else requestAnimationFrame(checkSize);
        };
        checkSize();
    }, []);

    // 상황별 다이얼로그 업데이트 로직
    useEffect(() => {
        if (!session || !dungeon) return;

        const room = session.grid[session.playerPos.y][session.playerPos.x];
        const status = session.encounterStatus;

        // 1. 위협 조우 시 최우선 메시지
        if (status === 'ENCOUNTERED') {
            setLastDiscoveryMessage(`CRITICAL ALERT: ${session.bossEntity?.name} identified. Power Level: ${bossPower} CP. Probability of escape: ${fleeChance}%.`);
            return;
        }

        // 2. 전투 종료 후 승리/패배 메시지 (도주 성공 텍스트는 handleFleeSuccess에서 수동 처리하므로 제외)
        if (status === 'VICTORY') {
            setLastDiscoveryMessage("High-Value Target neutralized. The area is now secure. Proceed to extraction to secure all loot.");
            return;
        }
        if (status === 'DEFEAT') {
            setLastDiscoveryMessage("CRITICAL FAILURE: Squad vitals are failing. Emergency extraction protocol required.");
            return;
        }

        // 3. 일반 상태(NONE)에서의 위치별 메시지
        if (status === 'NONE' && !showWithdrawAfterFlee) {
            if (room === 'ENTRANCE') {
                if (session.isBossDefeated) {
                    setLastDiscoveryMessage("Mission complete. Extraction point is clear. Secure the haul and return to the forge?");
                } else {
                    setLastDiscoveryMessage(`Infiltration of ${dungeon.name} complete. Scanning for objectives...`);
                }
            } else if (room === 'NPC' && !session.npcFound) {
                setLastDiscoveryMessage("Life-sign confirmed. Survivor identified. Initializing rescue protocols.");
            } else if (room === 'BOSS' && session.isBossDefeated) {
                setLastDiscoveryMessage("Area secure. High-Value Target neutralized. Search for remaining loot or head to extraction.");
            } else if (lastDiscoveryMessage.includes("identified") || lastDiscoveryMessage.includes("WITHDRAWAL") || lastDiscoveryMessage === "") {
                setLastDiscoveryMessage("Sector clear. No immediate hostiles detected.");
            }
        }
    }, [session?.playerPos, session?.encounterStatus, session?.isBossDefeated, dungeon?.name, bossPower, fleeChance, showWithdrawAfterFlee]);

    useEffect(() => {
        if (!isReady || !containerRef.current || !session || !dungeon) return;
        if (!gameRef.current) {
            const config: Phaser.Types.Core.GameConfig = {
                type: Phaser.AUTO, parent: containerRef.current, width: containerRef.current.clientWidth, height: containerRef.current.clientHeight, backgroundColor: 'transparent', transparent: true, scene: [DungeonScene],
                scale: { mode: Phaser.Scale.RESIZE, autoCenter: Phaser.Scale.CENTER_BOTH }
            };
            const game = new Phaser.Game(config);
            gameRef.current = game;
            game.scene.start('DungeonScene', { session, moveEnergy: dungeon.moveEnergy, bossEnergy: dungeon.bossEnergy, onMove: (dx: number, dy: number) => actions.moveInManualDungeon(dx, dy), cameraMode: cameraMode });
        } else {
            const scene = gameRef.current.scene.getScene('DungeonScene') as DungeonScene;
            if (scene) { scene.updateSession(session); scene.setCameraMode(cameraMode); }
        }
    }, [isReady, session, actions, dungeon, cameraMode]);

    if (!session || !dungeon) return null;

    const currentRoom = session.grid[session.playerPos.y][session.playerPos.x];
    const isOnBossTile = currentRoom === 'BOSS';
    const isOnEntranceTile = currentRoom === 'ENTRANCE';
    const isOnNPCTile = currentRoom === 'NPC';

    return (
        <div className="absolute inset-0 z-[100] bg-stone-950 flex flex-col animate-in fade-in duration-500 overflow-hidden">
            <div ref={containerRef} className={`absolute inset-0 z-0 transition-all duration-700 ${isBattle ? 'opacity-20 blur-lg scale-110' : 'opacity-100 scale-100'}`} />

            {isBattle && (
                <DungeonCombatView 
                    session={session} 
                    party={party} 
                    boss={session.bossEntity!} 
                    fleeChance={fleeChance}
                    onFinish={(win, finalParty) => {
                        actions.resolveCombatManual(win, false, finalParty);
                        if (!win) {
                            setTimeout(() => actions.retreatFromManualDungeon(), 1000);
                        }
                    }}
                    onFlee={handleFleeSuccess}
                />
            )}

            {!isBattle && (
                <div className="absolute top-20 left-4 z-50 flex flex-col gap-2 w-48 md:w-56 pointer-events-none">
                    <button onClick={() => setIsSquadStatusExpanded(!isSquadStatusExpanded)} className="bg-stone-950/40 backdrop-blur-md border border-white/10 rounded-lg p-2.5 flex items-center justify-between pointer-events-auto hover:bg-stone-900/60 transition-colors shadow-2xl">
                        <div className="flex items-center gap-2"><Shield className="w-4 h-4 text-blue-400" /><span className="text-[10px] font-black text-blue-100 uppercase tracking-widest">Squad Status</span></div>
                        {isSquadStatusExpanded ? <ChevronUp className="w-3.5 h-3.5 text-stone-500" /> : <ChevronDown className="w-3.5 h-3.5 text-stone-500" />}
                    </button>
                    {isSquadStatusExpanded && party.map(merc => {
                        const hpPer = (merc.currentHp / merc.maxHp) * 100;
                        const mpPer = (merc.currentMp / (merc.maxMp || 1)) * 100;
                        return (
                            <div key={merc.id} className={`bg-stone-900/80 border border-stone-700/50 p-3 rounded-xl backdrop-blur-md shadow-xl animate-in slide-in-from-top-2 duration-300 ${merc.currentHp <= 0 ? 'grayscale opacity-50' : ''}`}>
                                <div className="flex items-center gap-2.5 mb-2"><div className="w-8 h-8 rounded-full bg-stone-850 flex items-center justify-center border border-white/5 text-sm shadow-inner shrink-0">{merc.icon}</div><div className="min-w-0 flex-1"><div className="text-[11px] font-black text-white truncate leading-none uppercase">{merc.name.split(' ')[0]}</div><div className="text-[8px] text-stone-500 font-bold uppercase tracking-tighter truncate mt-0.5">{merc.job} • LV.{merc.level}</div></div></div>
                                <div className="space-y-1.5">
                                    <div className="flex flex-col gap-0.5">
                                        <div className="flex justify-between text-[7px] font-mono text-stone-400 px-0.5 uppercase tracking-tighter"><span>HP</span><span>{Math.floor(merc.currentHp)}</span></div>
                                        <div className="w-full bg-stone-950 h-1.5 rounded-full overflow-hidden border border-white/5 shadow-inner"><div className={`h-full transition-all duration-500 ${hpPer < 30 ? 'bg-red-600 animate-pulse' : 'bg-red-500'}`} style={{ width: `${hpPer}%` }} /></div>
                                    </div>
                                    <div className="flex flex-col gap-0.5">
                                        <div className="flex justify-between text-[7px] font-mono text-stone-400 px-0.5 uppercase tracking-tighter"><span>MP</span><span>{Math.floor(merc.currentMp)}</span></div>
                                        <div className="w-full bg-stone-950 h-1 rounded-full overflow-hidden border border-white/5 shadow-inner"><div className="h-full bg-blue-600 transition-all duration-500" style={{ width: `${mpPer}%` }} /></div>
                                    </div>
                                </div>
                            </div>
                        );
                    })}
                </div>
            )}

            <div className={`absolute bottom-0 left-0 right-0 z-40 px-[2%] pb-[2%] flex flex-col items-end pointer-events-none transition-all duration-500 ${isBattle ? 'translate-y-full opacity-0 scale-95' : 'translate-y-0 opacity-100 scale-100'}`}>
                <div className={`mb-4 transition-all duration-500 pointer-events-auto ${isEncountered ? 'opacity-0 scale-90 translate-y-4 pointer-events-none' : 'opacity-100 scale-100 translate-y-0'}`}>
                    <div className="grid grid-cols-3 gap-2 p-3 bg-stone-900/60 backdrop-blur-xl rounded-[2rem] border border-white/10 shadow-2xl" style={{ width: '18vmin', height: '18vmin', minWidth: '120px', minHeight: '120px' }}>
                        <div />
                        <button onClick={() => handleDpadMove(0, -1)} className="w-full h-full flex items-center justify-center rounded-xl border-2 transition-all bg-stone-800 border-stone-600 text-stone-200 active:scale-90 active:bg-amber-600 active:border-amber-400"><ChevronUp className="w-[70%] h-[70%]" /></button>
                        <div />
                        <button onClick={() => handleDpadMove(-1, 0)} className="w-full h-full flex items-center justify-center rounded-xl border-2 transition-all bg-stone-800 border-stone-600 text-stone-200 active:scale-90 active:bg-amber-600 active:border-amber-400"><ChevronLeft className="w-[70%] h-[70%]" /></button>
                        <button onClick={() => setCameraMode(prev => prev === 'LOCKED' ? 'ADAPTIVE' : prev === 'ADAPTIVE' ? 'FREE' : 'LOCKED')} className={`w-full h-full rounded-xl border flex items-center justify-center transition-all ${cameraMode !== 'FREE' ? 'bg-amber-500/20 border-amber-500/50 text-amber-500' : 'bg-stone-800/40 border-stone-700 text-stone-500'}`}>{cameraMode === 'LOCKED' ? <Lock className="w-[50%] h-[50%]" /> : cameraMode === 'ADAPTIVE' ? <Target className="w-[50%] h-[50%]" /> : <Unlock className="w-[50%] h-[50%]" />}</button>
                        <button onClick={() => handleDpadMove(1, 0)} className="w-full h-full flex items-center justify-center rounded-xl border-2 transition-all bg-stone-800 border-stone-600 text-stone-200 active:scale-90 active:bg-amber-600 active:border-amber-400"><ChevronRight className="w-[70%] h-[70%]" /></button>
                        <div />
                        <button onClick={() => handleDpadMove(0, 1)} className="w-full h-full flex items-center justify-center rounded-xl border-2 transition-all bg-stone-800 border-stone-600 text-stone-200 active:scale-90 active:bg-amber-600 active:border-amber-400"><ChevronDown className="w-[70%] h-[70%]" /></button>
                        <div />
                    </div>
                </div>
                <div className="w-full pointer-events-auto">
                    <DialogueBox 
                        speaker={isEncountered ? "Tactical AI" : "Exploration Link"} 
                        text={lastDiscoveryMessage} 
                        options={isEncountered ? [
                            { label: "ENGAGE TARGET", action: handleStartCombat, variant: 'primary' },
                            { label: `FLEE TO SAFETY`, action: () => handleFleeSuccess(party), variant: 'danger' }
                        ] : (isOnBossTile && (isVictory || isDefeat)) ? [
                            { label: isVictory ? "Secure Loot & Extract" : "Emergency Retreat", action: () => (isVictory ? actions.finishManualAssault() : actions.retreatFromManualDungeon()), variant: 'primary' }
                        ] : (isOnEntranceTile) ? [
                            { label: session.isBossDefeated ? "FINISH MISSION" : "Withdraw", action: () => (session.isBossDefeated ? actions.finishManualAssault() : setShowRetreatConfirm(true)), variant: 'primary' },
                            { label: "Continue Exploring", action: () => setLastDiscoveryMessage("Resuming exploration. Stay vigilant."), variant: 'neutral' }
                        ] : (isOnNPCTile && !session.npcFound) ? [
                            { label: "SECURE SURVIVOR", action: () => actions.rescueMercenary('tilly_footloose'), variant: 'primary' }
                        ] : (showWithdrawAfterFlee) ? [
                            { label: "Withdraw", action: () => setShowRetreatConfirm(true), variant: 'neutral' }
                        ] : []} 
                    />
                </div>
            </div>

            <ConfirmationModal isOpen={showRetreatConfirm} title="Abort Assault?" message="Confirm extraction to return the squad to safety. Unclaimed loot on this floor may be lost." onConfirm={() => actions.retreatFromManualDungeon()} onCancel={() => setShowRetreatConfirm(false)} isDanger={true} />
        </div>
    );
};

export default AssaultNavigator;

import { DerivedStats } from './Stats';

export interface Monster {
  id: string;
  name: string;
  level: number;
  icon: string;
  sprite?: string;
  description: string;
  stats: DerivedStats;
  currentHp: number;
  rewardXp: number; // 처치 시 지급될 총 경험치
}

import { GameState, ManualDungeonSession, RoomType, DungeonResult } from '../../types/game-state';
import { DUNGEONS } from '../../data/dungeons';
import { handleClaimExpedition } from './expedition';
import { MONSTERS } from '../../data/monsters';
import { calculateMaxHp, calculateMaxMp, mergePrimaryStats } from '../../models/Stats';

// ... (generateManualGrid 및 handleStartManualDungeon은 기존과 동일)

export const handleMoveManualDungeon = (state: GameState, payload: { x: number, y: number }): GameState => {
    const session = state.activeManualDungeon;
    if (!session || session.encounterStatus === 'ENCOUNTERED' || session.encounterStatus === 'BATTLE') return state;

    const dungeon = DUNGEONS.find(d => d.id === session.dungeonId);
    if (!dungeon) return state;

    const newX = session.playerPos.x + payload.x;
    const newY = session.playerPos.y + payload.y;

    if (newX < 0 || newX >= dungeon.gridWidth || newY < 0 || newY >= dungeon.gridHeight) {
        return { ...state, toastQueue: [...state.toastQueue, "Area boundary reached."] };
    }

    const targetRoom = session.grid[newY][newX];
    if (targetRoom === 'WALL') return state;

    const isAlreadyVisited = session.visited[newY][newX];
    const cost = isAlreadyVisited ? -1 : (targetRoom === 'BOSS' ? dungeon.bossEnergy : dungeon.moveEnergy);

    const party = state.knownMercenaries.filter(m => session.partyIds.includes(m.id));
    if (cost > 0 && party.some(m => (m.expeditionEnergy || 0) < cost)) {
        return { ...state, logs: [`Your squad is too exhausted to move.`, ...state.logs] };
    }

    let updatedMercs = state.knownMercenaries.map(m => {
        if (session.partyIds.includes(m.id)) {
            let nextEnergy = Math.max(0, (m.expeditionEnergy || 0) - cost);
            let nextHp = m.currentHp;
            if (targetRoom === 'TRAP' && !isAlreadyVisited) nextHp = Math.max(0, m.currentHp - 25);
            return { ...m, expeditionEnergy: nextEnergy, currentHp: nextHp };
        }
        return m;
    });

    // 전멸 체크: 모든 파티원의 체력이 0이 되면 탈락
    const isWipedOut = updatedMercs.filter(m => session.partyIds.includes(m.id)).every(m => m.currentHp <= 0);
    if (isWipedOut) {
        return handleRetreatManualDungeon({ ...state, knownMercenaries: updatedMercs });
    }

    const newVisited = [...session.visited.map(row => [...row])];
    newVisited[newY][newX] = true;

    let extraGold = 0;
    let newGrid = [...session.grid.map(row => [...row])];
    let logMsg = '';
    let encounterStatus: ManualDungeonSession['encounterStatus'] = 'NONE';

    if (targetRoom === 'GOLD' && !isAlreadyVisited) {
        extraGold = (dungeon.tier || 1) * 50;
        newGrid[newY][newX] = 'EMPTY';
        logMsg = `Cache secured. (+${extraGold} G)`;
    } else if (targetRoom === 'TRAP' && !isAlreadyVisited) {
        logMsg = `AMBUSH: Squad hit by a trap! (-25 HP)`;
    } else if (targetRoom === 'KEY' && !isAlreadyVisited) {
        logMsg = `Chamber key recovered.`;
        newGrid[newY][newX] = 'EMPTY';
    } else if (targetRoom === 'BOSS' && !session.isBossDefeated) {
        encounterStatus = 'ENCOUNTERED';
        logMsg = `CRITICAL ALERT: Boss identified.`;
    }

    return {
        ...state,
        knownMercenaries: updatedMercs,
        activeManualDungeon: {
            ...session,
            grid: newGrid,
            playerPos: { x: newX, y: newY },
            pathHistory: [{ x: newX, y: newY }, ...session.pathHistory].slice(0, 50),
            visited: newVisited,
            hasKey: targetRoom === 'KEY' ? true : session.hasKey,
            encounterStatus,
            goldCollected: session.goldCollected + extraGold
        },
        logs: logMsg ? [logMsg, ...state.logs] : state.logs
    };
};

export const handleResolveCombatManual = (state: GameState, payload: { win: boolean, flee: boolean, finalParty: any[] }): GameState => {
    const session = state.activeManualDungeon;
    if (!session) return state;

    let logMsg = '';

    // 경험치 분배: 승리 시 보스 경험치를 생존 파티원 수로 나눔
    const livingMembers = payload.finalParty.filter(p => p.currentHp > 0);
    const xpPerMember = (payload.win && session.bossEntity && livingMembers.length > 0) 
        ? Math.floor(session.bossEntity.rewardXp / livingMembers.length) 
        : 0;

    if (payload.win && xpPerMember > 0) {
        logMsg = `VICTORY: ${session.bossEntity?.name} defeated! ${livingMembers.length} members gained ${xpPerMember} XP.`;
    }

    const newKnownMercenaries = state.knownMercenaries.map(m => {
        const combatant = payload.finalParty.find(p => p.id === m.id);
        if (combatant) {
            let nextXp = m.currentXp;
            let nextLevel = m.level;
            let nextMaxHp = m.maxHp;
            let nextMaxMp = m.maxMp;
            let nextCurrentHp = combatant.currentHp;

            if (payload.win && combatant.currentHp > 0) {
                nextXp += xpPerMember;
                while (nextXp >= m.xpToNextLevel) {
                    nextXp -= m.xpToNextLevel;
                    nextLevel++;
                    const merged = mergePrimaryStats(m.stats, m.allocatedStats);
                    nextMaxHp = calculateMaxHp(merged, nextLevel);
                    nextMaxMp = calculateMaxMp(merged, nextLevel);
                    nextCurrentHp = nextMaxHp; // 레벨업 시 완치
                    logMsg += ` ${m.name} reached Level ${nextLevel}!`;
                }
            }

            return { 
                ...m, 
                currentHp: nextCurrentHp, 
                currentMp: combatant.currentMp,
                currentXp: nextXp,
                level: nextLevel,
                maxHp: nextMaxHp,
                maxMp: nextMaxMp,
                xpToNextLevel: nextLevel * 100
            };
        }
        return m;
    });

    return {
        ...state,
        knownMercenaries: newKnownMercenaries,
        activeManualDungeon: {
            ...session,
            encounterStatus: payload.win ? 'VICTORY' : (payload.flee ? 'NONE' : 'DEFEAT'),
            isBossDefeated: payload.win || session.isBossDefeated
        },
        logs: logMsg ? [logMsg, ...state.logs] : state.logs
    };
};

export const handleRetreatManualDungeon = (state: GameState): GameState => {
    const session = state.activeManualDungeon;
    if (!session) return state;

    const isDefeat = session.encounterStatus === 'DEFEAT' || 
                    state.knownMercenaries.filter(m => session.partyIds.includes(m.id)).every(m => m.currentHp <= 0);

    const dungeon = DUNGEONS.find(d => d.id === session.dungeonId);
    const mercResults: DungeonResult['mercenaryResults'] = [];

    const updatedMercs = state.knownMercenaries.map(m => {
        if (session.partyIds.includes(m.id)) {
            let nextStatus: any = 'HIRED';
            let statusChange: 'NONE' | 'INJURED' | 'DEAD' = 'NONE';

            if (isDefeat) {
                const roll = Math.random();
                if (roll < 0.1) { nextStatus = 'DEAD'; statusChange = 'DEAD'; }
                else { 
                    nextStatus = 'INJURED'; statusChange = 'INJURED'; 
                    m.recoveryUntilDay = state.stats.day + 2; 
                }
            } else if (m.currentHp <= 0) {
                nextStatus = 'INJURED'; statusChange = 'INJURED';
                m.recoveryUntilDay = state.stats.day + 1;
            }

            mercResults.push({
                id: m.id, name: m.name, job: m.job, levelBefore: m.level, levelAfter: m.level,
                xpGained: 0, currentXp: m.currentXp, xpToNext: m.xpToNextLevel, statusChange
            });

            return { ...m, status: nextStatus, assignedExpeditionId: undefined };
        }
        return m;
    });

    return {
        ...state,
        knownMercenaries: updatedMercs,
        dungeonResult: isDefeat ? {
            dungeonName: dungeon?.name || 'Unknown',
            rewards: [],
            mercenaryResults: mercResults,
            isDefeat: true
        } : state.dungeonResult,
        activeManualDungeon: null,
        showManualDungeonOverlay: false,
        logs: [isDefeat ? 'CRITICAL FAILURE: Squad neutralized.' : 'Squad retreated.', ...state.logs]
    };
};

export const handleRescueNPC = (state: GameState, payload: { npcId: string }): GameState => {
    const currentSession = state.activeManualDungeon;
    if (!currentSession) return state;

    let newGrid = [...currentSession.grid.map(row => [...row])];
    newGrid[currentSession.playerPos.y][currentSession.playerPos.x] = 'EMPTY';

    return {
        ...state,
        activeManualDungeon: { ...currentSession, grid: newGrid, npcFound: true, rescuedNpcId: payload.npcId },
        logs: [`Survivor secured! Initiating extraction.`, ...state.logs]
    };
};

